window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q07"]=window.__LIBQ["tien-nghich"]["q07"]||{};window.__LIBQ["tien-nghich"]["q07"]["cotTruyen"]=[{"chuong":635,"tieuDe":"Pháp Bảo Đặc Thù Của Liễu Mi","tomTat":"Vương Lâm nhìn vào ánh mắt trong màn sương đen và chấn động vì cảm giác máu huyết tương dung, lập tức thu chiêu rồi gọi Tiên vệ khôi lỗi bao phủ màn sương để khống chế oán ảnh. Liễu Mi tiết lộ nàng đã luyện hóa đứa nhỏ trăm năm thành oán ảnh, gieo vào ý thức nó rằng phụ thân đã vứt bỏ nó, và người phụ thân ấy chính là Vương Lâm. Sau cơn trầm mặc, Vương Lâm không sụp đổ mà cảm ơn Liễu Mi vì đã đưa đứa nhỏ trở lại, đồng thời khẳng định dù mất ngàn năm cũng sẽ khiến nó hồi phục. Sát khí của hắn bùng lên dữ dội, dùng Hoàng tuyền chỉ, Thất Tinh kiếm trận, Tịch Diệt chỉ và Định để áp đảo Liễu Mi, trong khi nàng chống đỡ bằng Cổ kính Hạ phẩm Tiên bảo và hắc châm Hồn thứ tư. Khi Liễu Mi gọi Lệ nhi khiến oán ảnh phát tiếng thê lương làm Vương Lâm đau đớn, hắn vẫn không dừng tay. Đúng lúc Liễu Mi lâm nguy, Huyễn gia Lão Tổ mở lốc xoáy cứu nàng, đưa cánh tay khô héo ra đối chưởng khiến Vương Lâm phun máu lùi lại. Vương Lâm tuyên bố Huyễn gia sẽ bị diệt tộc nếu cứu Liễu Mi, rồi phóng kiếm khí Lăng Thiên Hầu vào lốc xoáy truy kích. Kiếm khí làm lốc xoáy sụp đổ, chấn thương Huyễn gia Lão Tổ ở Nhà Tổ trên Thiên Huyễn Tinh, nhưng Liễu Mi vẫn được bạch quang cuốn về mật thất."},{"chuong":636,"tieuDe":"Vương Bình","tomTat":"Huyễn gia Lão Tổ dùng nguyên thần vượt tinh không cứu Liễu Mi, nhưng nhanh chóng nhận ra Vương Lâm không phải tiểu bối dễ giết vì nguyên thần đối phương có thể đánh tan một chỉ của lão và bên cạnh còn có Tiên vệ khôi lỗi cảnh giới Âm Dương hư thật. Kiếm khí của Lăng Thiên Hầu do Vương Lâm phóng ra phá sập lốc xoáy, truy vào nguyên thần lão với khí tức Tịnh Niết, buộc lão hoảng hốt chạy về mật thất Huyễn gia. Dù lão đánh tan thông đạo, kim mang vẫn lao ra làm mật thất nổ tung, chấn động Thiên Huyễn Tinh; Huyễn gia Lão Tổ phải vận Vạn Huyễn Vô Tướng đạo đối kháng nhưng vẫn bị kiếm khí xâm nhập thân thể. Lão nhớ lại lời uy hiếp diệt Huyễn gia của Vương Lâm, suy đoán sau lưng hắn có cao thủ Tịnh Niết, nhưng cuối cùng vẫn không giao Liễu Mi vì kế hoạch trên người nàng có thể giúp lão tiến thêm về tu vi. Sau khi tự trấn an rằng Vương Lâm đến từ Liên Minh Tinh Vực và khó có cao thủ vượt sang La Thiên, lão truyền thần thức cầu viện Thiên gia cùng Hứa gia. Trên Nhiễm Vân Tinh, Vương Lâm quay lại đối diện màn sương đen bị Tiên vệ vây quanh, nghe tiếng oán anh non nớt và đau đớn nhận ra đó là huyết mạch của mình. Dù đứa bé cắn hút máu và truyền oán khí âm hàn vào cơ thể, hắn vẫn dịu dàng đặt lại tên từ Lệ Nhi thành Vương Bình, mong con được bình an."},{"chuong":637,"tieuDe":"Đạo Nghĩa","tomTat":"Oán anh Bình nhi vẫn cắn đầu ngón tay Vương Lâm và truyền oán khí vào người hắn, nhưng lôi uy nguyên thần khiến oán khí không thể gây hại. Vương Lâm dùng cấm chế phong ấn đứa nhỏ, đưa vào Thiên nghịch không gian và để lại một phần nguyên thần để về sau xua oán khí cho con. Sau đó hắn thu hồi đệ tử hồn của Tôn Hồn Phiên, gặp Tôn Tích và nghe Tôn Tích thú nhận chuyện ba người từng giấu giếm để kéo hắn vào Hồn thủy làm người thế tội. Vương Lâm không truy cứu, vì đã nhận ba Tiên ngọc nên hứa bảo đảm hậu nhân ba nhà bình yên trăm năm, đồng thời tuyên bố Huyễn gia sẽ không còn tồn tại nếu bảo vệ Liễu Mi. Hắn phân tích cho Tôn Tích con đường khôi phục tu vi, rồi dùng Đạo hóa Hoàng Tuyền, Hoàng Tuyền lực và một viên Bát phẩm đan dược giúp Tôn Tích đạt lại Anh Biến trung kỳ, nhưng cũng khiến con đường tiến thêm của Tôn Tích bị khóa. Trước khi rời đi, Vương Lâm giao việc dàn xếp hậu nhân ba nhà cho Tôn Tích, sau đó xuyên qua Tỏa Tinh đại trận, dùng Tinh La bàn theo vị trí trong ngọc giản lao tới Thiên Huyễn Tinh. Trên đường, hắn suy đoán Huyễn gia thế lực phức tạp và Huyễn gia Lão Tổ có thể mời viện thủ nếu quyết bảo vệ Liễu Mi."},{"chuong":638,"tieuDe":"Kinh Thối Thiên Quỳ Tử","tomTat":"Huyễn Vô Tình triệu hồi trực hệ Huyễn gia về phía Nam Thiên Huyễn Tinh, mở hộ tộc đại trận và chuẩn bị cố thủ trong Nhà Tổ. Chương đồng thời xác lập thế cục ba đại gia tộc trên Thiên Huyễn Tinh: Thiên gia mạnh nhất, Huyễn gia đứng thứ hai nhờ truyền thừa tiên nhân, còn Hứa gia thần bí vì bị nghi có liên hệ với Đông Lâm Tinh. Thiên Quỳ Tử, một trong ba lão tổ Thiên gia, lấy tư cách cá nhân ra ngoài tinh không chặn Vương Lâm để đổi lấy bảo vật từ Huyễn gia. Vương Lâm cưỡi Tinh La bàn tới với sát ý, gọi Tiên vệ khôi lỗi giao chiến khiến Thiên Quỳ Tử vừa kiêng kị vừa nảy lòng tham. Khi Vương Lâm phóng Xạ Thần xa hóa thành Lôi Thú nuốt lôi phù văn, Thiên Quỳ Tử lầm tưởng hắn là người Lôi Tiên Điện, lập tức xin lỗi, bồi thường Tiên ngọc và tuyên bố Thiên gia không tham dự việc Huyễn gia. Sau đó Vương Lâm tiến vào Thiên Huyễn Tinh, tới phía trên Nhà Tổ Huyễn gia đòi giao Liễu Mi, trong khi Liễu Mi né tránh ánh mắt hắn và Huyễn Vô Tình thách hắn phá đại trận. Vương Lâm dùng Lôi Thú dẫn lôi công kích, rồi nhỏ máu mở phong ấn, khiến lôi uy bùng phát thành lốc và lưới lôi đình bên ngoài thân Lôi Thú."},{"chuong":639,"tieuDe":"Huyễn Gia Phân Liệt !","tomTat":"Vương Lâm ra lệnh phá trận, thúc Lôi Thú dồn lôi điện tới cực hạn công kích Huyễn gia đại trận, khiến tộc nhân Huyễn gia nhận ra biểu tượng Lôi Thú và liên hệ tới Lôi Tiên Điện nên hoảng sợ. Bên trong đại trận, bất mãn bị dồn nén vì việc Lão Tổ bảo hộ Liễu Mi bùng phát, nhiều tộc nhân cho rằng không đáng vì một ngoại nhân mà dẫn họa tới gia tộc. Huyễn Vô Tình quát mắng trấn áp phản đối, đồng thời âm thầm chờ Vương Lâm tiêu hao kiếm khí để tìm cơ hội ra tay. Lôi Thú và Tiên vệ khôi lỗi liên thủ ép đại trận nổi sóng dữ, làm trận pháp dần suy yếu. Huyễn Phong Thần, Tộc trưởng Huyễn gia, công khai chất vấn Lão Tổ, chỉ ra Vương Lâm có Lôi Thú và khôi lỗi mạnh nên đáng cân nhắc kết giao hơn là kết tử thù, rồi tuyên bố nếu trận bị phá sẽ thối lui để bảo toàn Huyễn gia. Khi đại trận bị ép tới cực hạn, Vương Lâm lấy Vũ Kiếm tiên do Chu Dật phân ly truyền thừa và thi triển Trảm La Quyết, khiến thiên địa như rơi vào hư ảo và làm Huyễn gia Lão Tổ chấn động nhận ra dấu hiệu quy tắc."},{"chuong":640,"tieuDe":"Trảm La Quyết !","tomTat":"Vương Lâm thi triển Trảm La Quyết, một kiếm ẩn chứa quy tắc khiến Huyễn Phong Thần, trực hệ Huyễn gia và các tu sĩ quan sát từ xa đều chấn động. Thiên Quỳ Tử nhận ra quy tắc trong kiếm thức, nghi ngờ Vương Lâm có liên quan Lôi Tiên Điện, còn lão già Hứa gia vốn định tương trợ Huyễn gia cũng dừng lại vì kiêng dè hậu thủ của hắn. Huyễn gia đại trận sụp đổ trước khi thực sự va chạm với công kích, nhưng Vương Lâm cũng tái nhợt vì Trảm La Quyết tiêu hao sự dung hợp giữa nguyên khí thân thể và nguyên thần. Huyễn Vô Tình không chịu lùi, mời Phúc Trạch ngọc giản, chí bảo Huyễn gia do tổ tiên ở Lôi chi Tiên giới để lại, đồng thời nghĩ tới di bảo tổ tiên đã mất tích cùng Huyễn Vô Tướng. Trước cục diện ấy, Huyễn Phong Thần dùng thân phận Tộc trưởng tuyên bố Huyễn gia không tham dự ân oán cá nhân giữa Vương Lâm và Huyễn Vô Tình, khiến nội bộ Huyễn gia tách khỏi lão tổ. Phúc Trạch ngọc giản hóa thành bóng người tỏa tiên lực áp chế toàn Thiên Huyễn Tinh và bước về phía Vương Lâm; Tiên vệ khôi lỗi cùng Lôi Thú lập tức hộ bên hắn, Liễu Mi do dự chạm túi trữ vật rồi buông tay. Ở thời khắc quyết định, Vương Lâm nhớ tới Oán Anh trong Tiên Nghịch không gian, gọi một tồn tại trong nguyên thần và hứa sau trận sẽ thả tự do."},{"chuong":641,"tieuDe":"Tán Ma Xuất Hiện","tomTat":"Trong lúc tiên khí của hư ảnh Tiên nhân đối trọng với ma khí, Vương Lâm gọi ra Tán Ma từ thiên linh cái, để lộ con bài mà hắn đã khắc lạc ấn khống chế hơn trăm năm nhưng chưa luyện hóa hoàn toàn. Sự xuất hiện của Tán Ma khiến Huyễn gia Lão Tổ tái mặt, Huyễn Phong Thần và tộc nhân Huyễn gia kinh sợ, Thiên Quỳ Tử run rẩy, còn lão già Hứa gia nhận ra lai lịch Cổ Ma của nó. Tán Ma đòi Vương Lâm thực hiện giao ước thả tự do sau trận, và Vương Lâm đồng ý dùng điều kiện ấy để đổi lấy chiến lực nhằm phá thế bảo hộ Liễu Mi. Tán Ma hóa sương mù nhập vào thất khiếu Vương Lâm, ma giáp bao phủ thân thể, tiên lực trong người hắn chuyển thành ma lực và dung hợp với ma hồn Tán Ma. Khi Tán Ma tung quyền hóa hắc long, hư ảnh Tiên nhân dùng tiên lực ngưng tụ thành lốc xoáy hóa giải, rồi thi triển Hoá Tiên Thuật rút linh lực toàn Thiên Huyễn Tinh, chuyển thành tiên lực và ngưng tụ thành vụ cầu màu trắng ngà. Tán Ma nhận ra thủ đoạn ấy thuộc một chi nhánh Cổ Yêu bộ tộc, bèn dùng ngôn ngữ Cổ Tộc gọi Cổ Ma, hóa ma trảo rút tinh hồn Thiên Huyễn Tinh để đối lại. Dù thân thể bị khống chế, Vương Lâm vẫn trực tiếp cảm nhận quá trình Cổ Ma rút tinh hồn và sinh ra cảm ngộ."},{"chuong":642,"tieuDe":"Cắn Nuốt","tomTat":"Tán Ma khống chế thân thể Vương Lâm thi triển Trừu hồn, rút tinh hồn Thiên Huyễn Tinh với quy mô khiến Vương Lâm nhớ đến Tham Lang từng rút Sơn hồn ở Yêu Linh chi địa nhưng hoàn toàn không thể so sánh. Tinh hồn tinh cầu va chạm với tiên lực của Tiên nhân hư ảnh, khiến linh mạch khô héo, mặt đất chấn động và tộc nhân Huyễn gia phải lui lại tự bảo vệ. Sau va chạm, Tiên nhân hư ảnh sụp đổ, Phúc Trạch ngọc giản hiện ra rồi vỡ vụn, chỉ còn lại một đạo phòng ngự cuối bao phủ mười dặm. Vương Lâm nhờ trực tiếp cảm nhận trận chiến này mà hiểu sâu hơn về thần thông, tiên lực và khoảng cách với tầng thứ bước thứ hai tu đạo. Khi Tán Ma tiếp tục công kích quầng sáng, Huyễn Phong Thần khuyên giao Liễu Mi để giữ mạng cho Huyễn gia, còn Liễu Mi van xin vì biết ra ngoài là chết. Huyễn Vô Tình cuối cùng lộ rõ ý đồ thật: muốn Liễu Mi giao ý cảnh để hắn đạt tới Vô Tướng Thiên Ma đạo, đồng thời chương hé lộ việc hắn thu nàng làm đệ tử vốn là để nuôi dưỡng rồi cắn nuốt Vạn Huyễn Thiên Ma đạo của nàng."},{"chuong":643,"tieuDe":"Cát Bụi Trở Về Với Cát Bụi","tomTat":"Huyễn Vô Tình vốn định chờ Liễu Mi đạt tới Âm Dương hư thật để ý cảnh lột xác hoàn chỉnh rồi mới cắn nuốt, nhưng vì Vương Lâm phá cục nên lão quyết định ra tay sớm. Liễu Mi hiểu rõ số phận của mình, đồng ý giao ý cảnh nhưng buộc Huyễn Vô Tình phải giết Vương Lâm, nếu không thì giao túi trữ vật của nàng cho hắn. Tán Ma khống chế thân thể Vương Lâm phá vỡ quầng sáng tiên lực cuối cùng của Huyễn gia, rồi nuốt sạch tia Vô Tướng Thiên Ma mà Huyễn Vô Tình cưỡng ép tạo ra và tiêu diệt luôn Huyễn Vô Tình. Liễu Mi mất sinh cơ vì ý cảnh cùng nguyên thần bị cắn nuốt, thân thể dần hóa thành những mảnh nhỏ bay đi. Vương Lâm nhận túi trữ vật nàng để lại, bên trong có một viên đan dược và một khối ngọc giản, nhưng hắn không diệt toàn tộc Huyễn gia mà rời đi trong mỏi mệt. Ở một tuyến khác, Tham Lang bôn tẩu trong tinh không La Thiên vì các lạc ấn trên thân đe dọa tính mạng. Nhiều ngày sau, Vương Lâm sống ẩn tại Lạc Nguyệt thôn trên Nhiễm Vân Tinh cùng đứa trẻ yếu bệnh tên Vương Bình, bắt đầu một quãng đời phàm tục giữa dân thôn."},{"chuong":644,"tieuDe":"Cả Đời Không Cần Tu Đạo","tomTat":"Vương Lâm sống tại thôn Lạc Nguyệt như một thợ mộc phàm tục, chăm sóc Vương Bình và bắt cậu uống thuốc đắng hằng ngày để trị oán khí. Đêm xuống, hắn dùng thần thông Lôi hệ ép hắc khí ra khỏi thân thể đứa trẻ, cho thấy Vương Bình vốn là Oán Anh, đã dùng đan dược do Liễu Mi lưu lại và bị Vương Lâm hủy ký ức cũ để bắt đầu một đời mới. Chương cũng kể lại việc Vương Lâm trở về Nhiễm Vân Tinh, chọn thôn Lạc Nguyệt vì nơi này giống quê cũ, rồi sống bằng nghề thợ mộc như mong muốn năm xưa của cha mình. Tôn Thái đã đến sống gần Vương Lâm từ năm thứ ba, nay già nua và tử khí nặng, rất yêu quý Vương Bình nhưng phải nghe Vương Lâm khẳng định sẽ không cho đứa trẻ tu đạo. Vương Lâm muốn bầu bạn với Vương Bình trọn một kiếp luân hồi, để con làm phàm nhân, cưới vợ sinh con rồi bình an trải qua sinh tử. Năm năm nữa trôi qua, thôn Lạc Nguyệt có người mất và trẻ nhỏ ra đời, Vương Bình mười tuổi nhưng vẫn nhỏ yếu, còn Vương Lâm cố ý để dung mạo già đi như người trung niên để hòa vào đời sống thôn xóm."},{"chuong":645,"tieuDe":"Tháo Giáp","tomTat":"Ở thôn Lạc Nguyệt, bà mối khuyên Vương Lâm tái hôn với nữ nhi Triệu gia vì Vương Bình đã mười tuổi và thiếu mẫu thân, nhưng Vương Lâm khéo léo từ chối. Vương Bình sợ có mẹ kế nên phản ứng mạnh, sau đó được cha hứa sẽ không tìm mẹ kế cho hắn; hắn uống thuốc và bộc lộ mong muốn ở bên phụ thân đến già. Đời sống phàm tục kéo dài khiến Vương Lâm gần như không dùng thần thông, chỉ âm thầm xua oán khí cho Vương Bình vào ban đêm. Qua việc nhìn con trưởng thành, đạo tâm của hắn dần thoát khỏi mệt mỏi, cảm ngộ sinh tử luân hồi sâu thêm và xuất hiện dấu hiệu thăng hoa về nhân quả tuần hoàn. Chương cũng dùng Liễu Mi và Huyễn Gia Lão Tổ để giải thích giá trị hiếm có của thăng hoa ý cảnh trong tu đạo. Sáu năm sau, khi Vương Bình mười sáu tuổi, Tôn Thái đại nạn, nghe Vương Lâm nhắc lời hứa năm xưa rồi an tường qua đời; lão được chôn sau núi cạnh thôn Lạc Nguyệt, mộ bia do Vương Bình khắc với thân phận nghĩa tôn."},{"chuong":646,"tieuDe":"Rời Đi","tomTat":"Sau khi Tôn Thái qua đời, thi thể lão hóa thành tro cốt và được Vương Lâm giữ trong túi trữ vật theo lời hứa. Thời gian trôi qua, Vương Bình trưởng thành trong Lạc Nguyệt thôn, học điêu khắc bên cha và được Vương Lâm dạy rằng mỗi nhát đao phải gắn với tâm ý cùng ký ức. Vương Bình hỏi về pháp thuật do Tôn Thái để lại, khiến Vương Lâm biết rõ chuyện Tôn Thái từng âm thầm truyền khẩu quyết tu đạo cho con mình, nhưng Vương Bình nói chưa từng tu luyện. Vương Lâm dứt khoát cấm Vương Bình bước vào tu đạo, khẳng định có thể cho con mọi thứ trên thế gian ngoại trừ con đường ấy. Ba năm sau, Vương Bình mười chín tuổi, dung mạo càng giống Liễu Mi, còn Vương Lâm quyết định thu dọn nhà cửa, dẫn con rời Lạc Nguyệt thôn sau mười chín năm. Người trong thôn đến tiễn biệt, Chu gia đại hán cảm khái năm tháng đã qua, còn Chu Nhược Đồng hỏi Vương Bình có trở về không và bật khóc khi nghe hắn nói có lẽ sẽ không."},{"chuong":647,"tieuDe":"Thăng Hoa","tomTat":"Trên Nhiễm Vân tinh, Vương Lâm không truyền đạo thuật cho Vương Bình mà dẫn con trai dùng thân phàm đi qua danh sơn, sông lớn và biển rộng để trực tiếp cảm nhận thiên địa. Ba năm leo núi khiến Vương Bình dần cứng cỏi, sau đó hành trình trên sông và ngoài biển tiếp tục mở rộng tâm linh hắn bằng sự liên miên, bao dung và mênh mông của tự nhiên. Tám năm sau, Vương Bình hai mươi bảy tuổi, dáng vẻ yêu dị tan đi, tâm cảnh đã đủ chứa núi sông biển trời dù vẫn là phàm nhân. Vương Lâm nhận ra oán khí trong linh hồn con chỉ còn một chút cuối cùng, nhưng phần này không còn pháp thuật hay đan dược nào khu trừ được, chỉ có thể chờ luân hồi hủy diệt. Khi trở lại gần Lạc Nguyệt thôn, Vương Bình không muốn vào thôn mà theo phụ thân lên Kỳ Liên phong, nơi họ chứng kiến dông tố tan đi và cầu vồng hiện ra. Một tu sĩ trung niên cưỡi phi kiếm màu xanh bay qua, tán thưởng nghị lực của phàm nhân leo núi rồi rời đi, khiến Vương Bình lần đầu thấy cảnh tượng tu tiên. Hắn hỏi phụ thân có thật sự không thể cho mình tu đạo hay không; Vương Lâm bi thương nhưng chỉ lắc đầu, khiến Vương Bình lặng im suốt đường xuống núi."},{"chuong":648,"tieuDe":"Thanh Nghi","tomTat":"Trên đường tới Kỳ Thủy thành, Vương Bình lần thứ hai xin phụ thân cho tu đạo, nhưng Vương Lâm vẫn từ chối vì một căn nguyên chỉ mình hắn biết, có liên hệ tới bản thân Vương Bình và cái chết của Liễu Mi. Hai cha con vào Kỳ Thủy thành, một phó đô phồn hoa của Đại Tần quốc trên Nhiễm Vân tinh, và Vương Lâm quyết định sẽ định cư tại đây. Tại tửu quán Tĩnh Nhã Hiên, dung mạo của Vương Bình khiến Thanh nhi sư muội chú ý, làm thanh niên tử y đi cùng nàng sinh ghen tức và nhiều lần nhục mạ hắn. Vương Bình bình tĩnh đáp trả, khiến lão nhân cẩm y bên cạnh mượn cớ giáo huấn thay gia trưởng, phóng đôi đũa nhằm phế hai tay hắn. Vương Lâm chỉ liếc một cái đã khiến đôi đũa mất lực, đồng thời làm lão nhân Kết Đan tâm thần tan rã, kim đan nứt và đan khí lẫn máu trào ra. Sau khi uống đan dược và bóp nát ngọc giản đưa tin, lão nhân ngã gục trước sự kinh hãi của mọi người; Vương Lâm lạnh lùng tuyên bố con trai mình không cần người khác giáo huấn rồi tiếp tục uống rượu."},{"chuong":649,"tieuDe":"Chỉ Một Lần Thôi","tomTat":"Trong tửu lâu Kỳ Thủy thành, lão nhân Kết Đan bị Vương Lâm làm đan khí tán loạn, còn thanh niên tử y của Tôn gia vừa định uy hiếp đã bị phất tay đánh ngã nhưng được tha mạng. Vương Bình chứng kiến uy thế của phụ thân nên bắt đầu hiểu rằng Vương Lâm không phải tu sĩ bình thường; đồng thời hắn trò chuyện với Thanh Nghi và biết sư tôn nàng đã bóp nát ngọc giản đưa tin. Ba lão nhân Tôn gia kéo tới, Tôn sư tổ nhìn ra Vương Bình có thiên tư đặc biệt rồi dùng linh quyết tạm khóa đan khí cho lão nhân Kết Đan. Khi nhóm Tôn gia ngăn đường, Vương Lâm chỉ tiến một bước đã khiến hai lão nhân Nguyên Anh trung kỳ lùi lại, ngay cả Tôn sư tổ Nguyên Anh viên mãn cũng tái mặt. Rời tửu lâu, Vương Lâm cảnh cáo Tôn gia rằng đây chỉ là một lần được tha, rồi nói với Vương Bình rằng mình từng có uyên nguyên và từng hứa che chở Tôn gia một trăm năm bình an. Sau đó hai cha con mua một đại viện ở phía bắc Kỳ Thủy thành để định cư, trong khi chi nhánh Tôn gia vì lời cảnh cáo ấy mà nổi lên biến động lớn."},{"chuong":650,"tieuDe":"Yêu Cầu Của Vương Bình","tomTat":"Sau hơn hai mươi năm, Tôn gia nhờ nguyên do Tôn Tích đã thay thế địa vị Nhiễm gia tại Nhiễm Vân tinh, trở thành thế lực độc tôn và dần sinh ngạo khí. Tại chi nhánh Tôn gia ở Kỳ Thủy thành, ba trưởng lão Hóa Thần thẩm vấn những người liên quan vụ tửu lâu, nghe lại lời cảnh cáo của Vương Lâm và phán đoán đối phương ít nhất có thể là Anh Biến kỳ; Thanh Nghi dù run sợ vẫn che giấu họ tên Vương Lâm. Ở đại viện phía bắc Kỳ Thủy, Vương Lâm thay biển thành Vương Phủ, giữ lại người hầu cũ rồi nói với Vương Bình rằng sau đời thường và mạo hiểm, hắn sẽ cho con ba mươi năm phú quý. Vương Bình hiểu đó là sự bù đắp vì mình không được tu đạo, nhưng yêu cầu nếu phải đi đường phàm nhân thì muốn tự mình trở thành chí tôn trong phàm nhân. Vương Lâm chấp thuận, trao hư ảnh bảo hộ dung nhập sau lưng Vương Bình và nói ở Nhiễm Vân tinh hắn có thể làm được hết thảy. Đêm ấy hai cha con đều giấu nỗi đau: Vương Lâm biết con không thể tu đạo, còn Vương Bình chỉ muốn tu đạo để mãi ở bên phụ thân. Ba ngày sau, Tôn Khải Minh với thân phận phó gia chủ Tôn gia và tu vi Anh Biến hậu kỳ tới Kỳ Thủy, được chi nhánh nghênh đón và bắt đầu nghi ngờ người gây chuyện có thể là Vấn Đỉnh lão quái."},{"chuong":651,"tieuDe":"Chia Lìa","tomTat":"Tôn gia ở Kỳ Thủy Thành tìm tới Vương phủ sau chuyện Vương Bình, nhưng Tôn Khải Minh quở trách tộc nhân vì không biết tốt xấu và có thể dẫn đại địch tới gia tộc. Trước Vương phủ, lão nhân mặt đỏ xông vào liền bị lực lượng vô hình chấn thương, khiến Tôn Khải Tinh nhận ra khí tức Vấn Đỉnh và lập tức cung kính rút lui; sau đó ông cấm toàn tộc bước vào phạm vi một ngàn trượng quanh nơi ở của vị tiền bối. Chương cũng xác lập Vân Vô Phong là tộc nhân Vân gia trên Vân Hải tinh, ở lại Nhiễm Vân tinh vì Thanh Nghi, rồi hoảng sợ khi nhớ lời cảnh báo rằng Hứa Mộc từng quét sạch Huyễn gia. Khi Thanh Nghi bị phong tu vi và đưa tới phòng Vân Vô Phong, Vương Lâm xuất hiện từ bóng đêm, đánh ngã hắn, chọn Thanh Nghi đi theo giúp Vương Bình và hứa đưa nàng tới đạo hạnh Nguyên Anh. Ba ngày sau, Vương Bình rời Kỳ Thủy Thành cùng Thanh Nghi để theo đuổi lý tưởng không muốn sống bình thản. Vương Lâm ở lại một mình, uống say lần đầu sau tám trăm năm trong đêm chia lìa và giữ lời không dùng thần thức truy tìm con trai. Ba năm sau, Bắc bộ Nhiễm Vân tinh xuất hiện Thiên Hành phái trong phàm nhân, phát triển mạnh với lời đồn về một thủ lĩnh như tiên nhân luôn có nữ nhân bên cạnh; thêm bảy năm nữa, Vương Lâm ngày càng già nua."},{"chuong":652,"tieuDe":"Năm Tháng","tomTat":"Thiên Hành phái phát triển nhanh trong dân gian, lan tới Kỳ Thủy thành và hơn nửa Nhiễm Vân Tinh, còn Vương Lâm già nua vẫn sống lặng lẽ như một phàm nhân, ngày ngày tới tửu quán uống rượu nghe chuyện thế sự. Ở đô thành Đế Sơn quốc, Vương Bình đã gần bốn mươi tuổi, ngồi trước bản đồ trong điện phủ xa hoa, nhớ tới phụ thân và được Thanh Nghi chăm sóc bên cạnh. Năm tháng trôi qua, Thiên Hành phái bao phủ ba đại đế quốc; khi Đế Sơn quốc toàn lực chèn ép, Thiên Hành phái dựa vào mạng lưới giáo chúng trong triều đình và quân đội để phản kích, nhanh chóng đoạt binh quyền. Đế Sơn quốc bị thay thế bởi Thiên Hành đế quốc, Vương Bình mặc long bào trở thành quân chủ, còn Thanh Nghi đứng bên cạnh hắn. Sau đó Đại Tần và Trần Vân xé bỏ minh ước, chiến tranh ba nước bùng lên, tu sĩ cũng nhúng tay nhưng đều bại lui khi Vương Bình thân chinh, lại thêm mệnh lệnh từ ba gia tộc Triệu, Nhiễm, Tôn khiến tu sĩ dần rời khỏi chiến tranh phàm nhân. Vương Lâm trở về Vương phủ trong tuổi già phàm tục, lặng nghĩ Bình nhi đã bốn mươi bảy tuổi và có thể đã nhận ra manh mối. Trong doanh trướng, Vương Bình dù đứng trên đỉnh quyền lực vẫn không khoái hoạt, mệt mỏi nhớ về thời thiếu niên ở sơn thôn, còn Thanh Nghi dịu dàng hỏi hắn có muốn trở lại nơi thơ ấu ấy hay không."},{"chuong":653,"tieuDe":"Mẫu Thân","tomTat":"Vương Bình cùng Thanh Nghi và quân sĩ trở lại thôn Lạc Nguyệt sau nhiều năm, nhìn cảnh cũ đổi thay và gặp lại Chu Nhược Đồng, người nay đã có chồng con. Con gái Chu Nhược Đồng tên Hứa Niệm Bình khiến hắn xúc động, nhưng hắn không quay lại mà lên hậu sơn tế bái mộ Tôn Thái rồi tiếp tục đi theo đại quân. Ở La Thiên Bắc Vực, Tham Lang cảm ứng được bảo vật trên một tinh cầu quỷ dị bị sương mù và mây tía che phủ, lấy đại đỉnh màu đen tiến vào tìm kiếm. Nhiều năm sau, Đại Tần và Trần Vân thuần phục, Thiên Hành trở thành quốc gia duy nhất trên Nhiễm Vân Tinh, hoàn thành chí nguyện thế tục của Vương Bình. Mười năm làm chí tôn khiến Vương Bình mỏi mệt; hắn nhường giang sơn cho thần tử thân tín rồi cùng Thanh Nghi trở về Vương phủ, nơi Vương Lâm đã chờ và chuẩn bị bữa cơm. Khi Vương Bình hỏi về mẫu thân, Vương Lâm kể lại quá khứ từ Chu Tước Tinh, Liễu Mi đến nguồn gốc của đứa nhỏ, khiến Vương Bình đau đớn nhận ra mình là oán anh bị mẫu thân luyện hóa. Sáng hôm sau, Vương Bình rời cha không nói lời nào và cùng Thanh Nghi quy ẩn ở một sơn thôn biên thùy, trở lại với điêu khắc tượng gỗ. Vương Lâm tiếp tục sống bình lặng thêm mười năm, từ cây cối sinh diệt, hoa tàn nở và mây tan tụ mà hiểu sâu hơn về sinh tử luân hồi, cân bằng và nhân quả."},{"chuong":654,"tieuDe":"Sứ Giả Lôi Tiên Điện Chân Chính","tomTat":"Vương Lâm sống lặng lẽ trong căn phòng lớn ở Vương phủ, để trẻ nhỏ chung quanh lui tới chơi đùa, lòng dần yên tĩnh vì cho rằng những điều cần nói với Vương Bình đã nói xong. Vương Bình tuổi già vẫn khắc tượng phụ thân, bộc bạch với Thanh Nghi rằng nếu có kiếp sau chỉ muốn cùng Vương Lâm sống như người thường trong một sơn thôn nhỏ, đồng thời thừa nhận còn một nghi vấn không dám hỏi về việc phụ thân không cho mình tu đạo. Thanh Nghi ở bên hắn đến cuối đời, dù có tu vi Nguyên Anh hậu kỳ đại viên mãn và ý cảnh tình yêu không hối hận vẫn chọn tình cảm phàm nhân hơn con đường thần tiên vô tình. Trong tinh không, Lôi Đạo Tử cưỡi Lôi Thú, lấy thân phận sứ giả Lôi Tiên Điện chân chính tiến về Nhiễm Vân tinh để điều tra nghi án giả mạo sứ giả sau biến cố Thiên Huyễn Tinh bảy mươi năm trước. Đêm tuyết dữ dội, Vương Bình cảm nhận sinh mệnh sắp hết, tiếp tục khắc pho tượng cuối cùng, dặn sau khi mình chết hãy đốt các tượng và nói đã sớm tha thứ cho phụ thân. Khi Lôi Đạo Tử giáng lâm, lôi uy làm trời đất Nhiễm Vân tinh biến đổi, toàn bộ tu sĩ cảm nhận khí tức khổng lồ; Tôn Tích rời bế quan lên không trung, còn Tôn Khải Tinh nhận định người đến không có ý tốt."},{"chuong":655,"tieuDe":"Kinh Biến","tomTat":"Nhiễm gia và Triệu gia được nhắc là không còn bằng Tôn gia vì nhiều cao thủ đã rời đi từ lâu. Tại Kỳ Thủy thành, Vương Lâm đang sống lặng lẽ trong Vương gia đại viện như một lão nhân thì Lôi Đạo Tử cưỡi lôi thú xuất hiện trên Nhiễm Vân tinh, dùng thần thức mang lôi uy quét khắp tinh cầu khiến tu sĩ kinh động, yêu vật run rẩy và phàm nhân hôn mê. Ban đầu Lôi Đạo Tử không chú ý tới Vương Lâm và định rời đi, nhưng hắn bất ngờ phát hiện Vương Bình trong một thôn nhỏ không bị thần thức làm ngất. Thanh Nghi bị uy áp làm phun máu nhưng vẫn vận linh lực chắn trước Vương Bình, còn Vương Bình bình tĩnh đối diện Lôi Đạo Tử và hỏi thân phận đối phương. Khi Lôi Đạo Tử nhìn ra Vương Bình không phải người, Vương Lâm ở xa lập tức cảm ứng nguy cơ, bóp tan bầu rượu và ánh mắt bùng hàn quang. Tiên vệ khôi lỗi từ bóng Vương Bình hiện thân, tung quyền đánh xuyên lôi quang khiến Lôi Đạo Tử lùi lại và nhận ra phẩm cấp cực cao của khôi lỗi. Lôi Đạo Tử sau đó gom điện quang vào chân giẫm xuống, phá tan căn phòng và để lôi quang lan rộng, đe dọa trực tiếp Vương Bình cùng Thanh Nghi. Trước nguy cơ ấy, Thanh Nghi nắm tay Vương Bình, còn Vương Bình vẫn không hoảng loạn vì tin phụ thân mình nhất định sẽ tới và là tồn tại mạnh nhất dưới vòm trời."},{"chuong":656,"tieuDe":"Tu Vi","tomTat":"Lôi quang của Lôi Đạo Tử áp sát Vương Bình thì một giọng nói tang thương vang lên chữ Định, khiến điện quang đông cứng; Vương Lâm từ lốc xoáy bước ra, phá tan lôi quang và cứu con trai. Nhận ra thôn dân đã bị thần thức quét qua làm bất tỉnh, Vương Lâm dùng ánh sáng dịu dàng bao lấy Vương Bình và Thanh Nghi, đưa hai người rời khỏi thôn tới bình nguyên phía tây Nhiễm Vân tinh. Lôi Đạo Tử đuổi theo, đòi Vương Lâm giao tiên vệ khôi lỗi để đổi lấy đường sống, nhưng Vương Lâm tuyên bố đối phương suýt giết con trai mình nên hôm nay phải chết. Tiên vệ khôi lỗi lao vào tấn công Lôi Đạo Tử nhưng bị lôi võng vây khốn, còn Lôi Đạo Tử tự xưng sứ giả Lôi Tiên Điện và tin rằng Vương Lâm không dám giết mình. Vương Lâm nuốt trọn lôi quang của đối thủ, tạo lôi cầu hút lôi lực thiên địa, khiến Lôi Đạo Tử phải dùng thiết côn khắc phù thu lôi nhưng pháp bảo này không chịu nổi, nứt vỡ rồi sụp đổ, kéo theo lôi võng tan rã. Sau khi pháp bảo bị phá, Lôi Đạo Tử nhận ra Vương Lâm chính là Hứa Mộc từng giả mạo sứ giả Lôi Tiên Điện, rồi kinh hãi khi thấy tiên lực và ý cảnh của Vương Lâm lần lượt dâng lên tới Vấn Đỉnh hậu kỳ trước khi tạm ngừng."},{"chuong":657,"tieuDe":"Im Mồm","tomTat":"Trên không trung Nhiễm Vân tinh, ý cảnh luân hồi của Vương Lâm hiện thành tranh sơn thủy và hoàng tuyền rồi thu vào thiên linh, khiến Lôi Đạo Tử nhận ra ý cảnh ấy đã chạm tới Vấn Đỉnh hậu kỳ đỉnh nhưng chưa vượt bước đầu tiên. Lôi Đạo Tử ngoài mặt mỉa mai Vương Lâm giả mạo sứ giả Lôi Tiên Điện, song trong lòng vẫn nghi ngờ vì lôi hệ thần thông và lớp che giấu tu vi do ý cảnh nhân quả tuần hoàn tạo ra. Khi Vương Lâm nâng tu vi, thân hình Vương Bình dao động từ linh hồn, còn Thanh Nghi nắm tay trấn an rằng nàng sẽ ở cạnh hắn bất luận thế nào. Lôi Đạo Tử thi triển Lôi chi tiên thú, gọi ra lôi thú của Lôi Tiên Điện để chứng minh thân phận, nhưng Vương Lâm đáp lại bằng Xạ Thần Xa hóa thành Ngân Giác lôi thú có lôi uy áp đảo. Hai lôi thú lao vào tử đấu, khiến Lôi Đạo Tử nổi tham niệm muốn giết Vương Lâm để đoạt thú vô chủ. Hắn dùng phi kiếm bạc và Lôi tiên kiếp tấn công, nhưng Vương Lâm lấy tiên bút vẽ bảy phù văn lôi, dung nhập nguyên thần mang thiên lôi thái cổ, phá tan tử lôi và khiến Lôi Đạo Tử lần đầu thua trên phương diện lôi điện thần thông. Sau khi khôi phục nhờ tiên lực cùng nguyên lực thiên địa, Lôi Đạo Tử uy hiếp sẽ thi triển nguyên lực pháp thuật bước thứ hai nếu Vương Lâm không giao Ngân Giác lôi thú và khôi lỗi. Vương Lâm rút đại kiếm muốn trực diện trải nghiệm nguyên lực thần thông của Âm Hư tu sĩ, nhưng khi Lôi Đạo Tử nhìn sang Vương Bình và nhắc tới một người chết, hắn bùng sát ý đỏ mắt, lạnh lùng quát im mồm."},{"chuong":658,"tieuDe":"Thần Thông Bước Thứ Hai","tomTat":"Lôi Đạo Tử vận dụng thần thông ở hai mắt để nhìn người đứng sau Vương Lâm và phát hiện Vương Bình là oán anh. Khi thấy trong thân thể Vương Bình có hai đạo kiếm khí cực kỳ đáng sợ, hắn lập tức bỏ ý định giao chiến trực diện và quay đầu chạy về phía lôi thú. Vương Lâm nổi giận, nâng đại kiếm thi triển Trảm La quyết bằng nguyên thần phối hợp nguyên lực, khiến Lôi Đạo Tử cảm nhận nguy cơ sinh tử. Bị ép đến đường cùng, Lôi Đạo Tử dùng nguyên lực lôi đỉnh, biến thiên địa thành cự đỉnh màu lam để luyện hóa đối thủ bằng lôi điện và đạo niệm. Trong lôi đỉnh, Vương Lâm chịu đạo niệm thần lôi liên tục oanh kích nhưng vẫn dùng Trảm La quyết chém vào quy tắc thiên địa, khiến cấu trúc đại đỉnh sụp đổ. Tiên vệ khôi lỗi và lôi thú của Vương Lâm cũng cùng công kích, làm đại đỉnh rung chuyển dữ dội và buộc Lôi Đạo Tử tiếp tục tiêu hao nguyên lực để duy trì."},{"chuong":659,"tieuDe":"Một Đời Luân Hồi, Chấm Dứt…","tomTat":"Trong đại đỉnh của Lôi Đạo Tử, thần lôi và lửa tím hợp thành thế lôi hỏa khiến Vương Lâm chịu áp lực nặng nề. Vương Lâm dùng máu vẽ phù văn, mở đạo phong ấn thứ ba trên lôi thú, khiến lôi quang hóa đen và khí tức viễn cổ áp đảo lôi thú của Lôi Tiên Điện. Tiên vệ bộc phát kim quang pha hồng quang, cùng lôi thú và Trảm La của Vương Lâm hợp lực phá nát đại đỉnh, khiến Lôi Đạo Tử trọng thương bỏ chạy. Sau trận chiến, Vương Bình hỏi cha về chân tướng, tự nhận ra mình đã chết từ sớm và chỉ là một tia hồn phách oán anh được kiếm khí cùng pháp thuật duy trì suốt hơn bảy mươi năm. Vương Bình từ biệt Vương Lâm và Thanh Nghi rồi tan thành kiếm khí, chỉ còn dải sáng trắng mang tia oán khí cuối cùng. Vương Lâm xóa sạch tia oán khí ấy, đưa hồn tức Vương Bình vào Thiên Nghịch bên cạnh nguyên anh Lý Mộ Uyển và nhận Uyển Nhi là mẫu thân của con. Thanh Nghi xin được đi theo Vương Bình bằng linh hồn, khẳng định không hối hận, còn Vương Lâm rời đi khi dáng vẻ già nua tan biến, khép lại một đời luân hồi bảy mươi năm."},{"chuong":660,"tieuDe":"Tiên Vệ Thứ Hai","tomTat":"Sau một đời luân hồi gắn với Vương Bình và chính bản thân mình, Vương Lâm nhận ra tu vi đã đột phá tới Vấn Đỉnh trung kỳ, ý cảnh đạt Vấn Đỉnh hậu kỳ, nhưng muốn thật sự phát huy cảnh giới cao hơn vẫn cần tiên ngọc và thiên địa nguyên lực. Hắn tự xét nếu gặp tu sĩ Âm Hư thì có thể chiến nhưng rất gian nan, còn Dương Thực thì không thể địch, nên càng xác định phải tăng tích lũy. Vương Lâm dùng Tinh La bàn truy theo tiên vệ và lôi thú, phát hiện Lôi Đạo Tử đang bị tiên vệ khôi lỗi cùng lôi thú đã giải phong ấn thứ ba vây ép đến nguyên lực gần cạn. Để tránh hậu hoạn từ Lôi Tiên Điện, hắn triển khai sát cục bằng Thất Tinh kiếm trận, Tôn Hồn Phiên, ba chung cực chủ hồn, tiên vệ và lôi thú công phá lôi mạc của Lôi Đạo Tử. Lôi Đạo Tử ngoài mặt xin tha và chấp nhận để Vương Lâm lưu dấu vết, nhưng trong lòng vẫn tính khôi phục nguyên lực rồi phá cấm báo thù. Vương Lâm dùng Cấm Phiên hạ võng cấm chế vào nguyên thần hắn, sau đó đưa hắn tới một tinh cầu xám hoang phế và mở động phủ tạm. Tại đây Vương Lâm lộ mục đích thật là luyện Lôi Đạo Tử thành tiên vệ thứ hai, rồi dùng nguyên thần khí và Côn Cực Tiên rút nguyên thần đối phương khỏi thân thể, mở màn quá trình luyện chế."},{"chuong":661,"tieuDe":"Tham Lang Đáng Thương","tomTat":"Khi Lôi Đạo Tử vừa muốn phản kháng, Vương Lâm lập tức vận dụng tiên vệ khôi lỗi, lôi thú, ba chung cực chủ hồn, Thất Tinh kiếm trận và cấm chế điện quang để khóa chặt nguyên thần hắn, không cho trở về thân thể. Vương Lâm nhân lúc Lôi Đạo Tử trọng thương, nguyên lực gần cạn, dùng nguyên thần khí và cấm chế tế luyện thân thể hắn, khiến Lôi Đạo Tử dần nhận ra mình đang bị luyện thành tiên vệ khôi lỗi. Sau đó Vương Lâm triệu Hoàng Tuyền lực trên tinh cầu bỏ hoang, hút khoáng thạch kim loại từ lòng đất luyện thành ba dịch cầu màu vàng, rồi đặt một dịch cầu vào mi tâm thân thể Lôi Đạo Tử, đẩy thân thể khôi lỗi tới ngân cấp. Trước sự phản kháng của Lôi Đạo Tử, Vương Lâm dùng hai đạo kiếm khí trấn áp và đưa ra điều kiện làm khôi lỗi ba ngàn năm thì sẽ được tự do. Ở Vân Hà tinh thuộc La Thiên Tinh Vực, Tham Lang quần áo rách nát, chật vật thử trốn khỏi tử địa lần thứ tám trong bảy mươi năm cùng một cái đỉnh lớn. Hắn vừa lao khỏi sương mù thì bị xúc tu từ trong tinh cầu quấn lấy kéo trở xuống, tuyệt vọng oán trách Vương Lâm khiến mình lưu lạc tới nơi đáng sợ này."},{"chuong":662,"tieuDe":"Bản Tiên Thuật Thiếu Của Vương Lâm","tomTat":"Nửa năm sau, tại động phủ trên tinh cầu bỏ hoang, Vương Lâm bước ra sau khi tế luyện tiên vệ thứ hai từ Lôi Đạo Tử và đầu lôi thú nhưng thất bại ở bước cuối. Tuy không luyện thành trung phẩm tiên vệ, hắn vẫn giữ được một thân thể ngân cực đỉnh phong, chỉ có thể làm động tác đơn giản dưới thần thức hiện tại. Sau thất bại, Vương Lâm ổn định đạo tâm, thu hai tiên vệ và xác định việc trọng yếu là nâng tu vi bản thân lên ngang bằng ý cảnh. Lôi thú sau khi mở phong ấn thứ ba không chịu trở lại Xạ Thần Xa hay túi trữ vật, tỏ ra linh động như có linh hồn riêng nên hắn tạm để nó tự do. Vương Lâm mở túi trữ vật vô chủ của Lôi Đạo Tử, chú ý ngọc giản khắc lôi thú, lôi kiếm, khoáng thạch bạc và tiên ngọc. Nhờ lôi uy Thái Cổ trong nguyên thần, hắn phá lôi quang trong ngọc giản và phát hiện Đỉnh Hóa Thiên Địa cùng Lôi Nguyên Thuật, trong đó Lôi Nguyên Thuật là bản thiếu hạ phẩm tiên thuật cực kỳ phù hợp với cơ duyên nguyên thần lôi của hắn. Sau đó hắn thu lôi kiếm, thử khoáng thạch bạc khiến lôi đình nhập thể sinh ra chút nguyên lực thiên địa, rồi cất lại để tính toán về sau."},{"chuong":663,"tieuDe":"Bản Tôn, Thác Sâm, Chu Như","tomTat":"Vương Lâm kiểm kê túi trữ vật của Lôi Đạo Tử, phát hiện lượng tiên ngọc cực lớn và từ đó nhận ra nội tình Lôi Tiên Điện vượt xa tưởng tượng. Hắn rời động phủ trên tinh cầu bỏ hoang, san phẳng phạm vi ngàn dặm, bố trí tiên ngọc, Tôn Hồn Phiên, ba chủ hồn và tiên vệ khôi lỗi để bế quan thôn phệ tiên khí tăng tu vi. Ở Liên Minh Tinh Vực, Tử Tâm cùng hai huyết nô Vấn Đỉnh tới điều tra một tiểu tinh cầu hoang dã thuộc phạm vi Huyết Tổ, nhưng khi thần thức dò sâu thì bị tiếng quát uy nghiêm trong lòng tinh cầu đánh bật và buộc phải rút lui. Tinh cầu sau đó tan vỡ, hai huyết nô tự bạo nguyên thần để giúp Tử Tâm kích hoạt ngọc giản huyết sắc, còn trung tâm tinh cầu lộ ra bản tôn Vương Lâm với tóc đỏ và bốn tinh điểm chưa hoàn chỉnh. Bản tôn thử Trừu Hồn nhưng chưa thành thục, nghĩ tới cổ thần chi khí, Chu Tước Tinh và Thác Sâm, rồi vài tháng sau chọn một tinh cầu có tầng lôi quang tự nhiên để tiếp tục tu luyện. Tại Cổ Thần Chi Địa trong Tu Ma Hải, Thác Sâm khắc đầy tên Vương Lâm trên cột đá, tuyên bố sắp thoát khốn và phái sứ giả rời đi; người này chính là Thiên Ma Tán Nhân vốn đã chết từ lâu. Trên đỉnh Chu Tước Sơn, Chu Như mở túi trữ vật Vương Lâm lưu lại, nhận bạch quang nhập mi tâm, khôi phục ký ức phong ấn và bật khóc khi hiểu Vương Lâm vẫn không muốn nàng đi tìm hắn."},{"chuong":664,"tieuDe":"Tu Đạo Bước Thứ Bốn…","tomTat":"Vương Lâm bế quan hấp thu lượng lớn tiên ngọc trong gần một năm, nhờ nguyên thần biến dị mà đột phá từ Vấn Đỉnh trung kỳ lên Vấn Đỉnh hậu kỳ. Sau khi xuất quan, hắn cưỡi lôi thú ngân sừng đi trong tinh không, khí thế và lôi quang khiến dáng vẻ rất giống sứ giả Lôi Tiên Điện. Trên đường, hắn hồi tưởng hơn chín trăm năm tu đạo, nhớ ân cứu mạng của Chu Dật, suy ngẫm về ba bước tu đạo và tự hỏi liệu sau bước thứ ba còn có bước thứ tư hay không. Vì cần nhiều Thăng Tiên quả và không muốn trở lại ký ức đau buồn ở Nhiễm Vân Tinh, hắn quyết định tới Thiên Huyễn Tinh tìm Huyễn Gia; đồng thời nghĩ tới Vọng Nguyệt trên Vân Hà tinh, Cổ Thần Khí và thần điêu đầu tinh của sứ giả Tu Chân Liên Minh. Lôi thú giáng lâm Thiên Huyễn Tinh tạo lôi vân, lôi đình và uy áp khiến tu sĩ chấn động, buộc Huyễn Phong Thần dẫn Huyễn Gia ra nghênh tiếp. Trước thân phận sứ giả Lôi Tiên Điện mà Vương Lâm thể hiện, Huyễn Phong Thần chấp nhận giao toàn bộ Thăng Tiên quả, dù như vậy là bỏ cơ hội vào Lôi Chi tiên giới sau trăm năm. Khi nhận ra số Thăng Tiên quả ấy vẫn chưa đủ, Vương Lâm nảy ý mượn danh Lôi Tiên Điện để tới La Thiên Bắc Vực chiếm đoạt thêm."},{"chuong":665,"tieuDe":"Phụ Thuộc","tomTat":"Vương Lâm sau khi lấy Thăng Tiên quả của Huyễn gia liền cưỡi Lôi Thú tới Thiên gia trên Thiên Huyễn Tinh. Thiên Quỳ Tử vừa kiêng dè uy danh Sứ giả Lôi Tiên Điện vừa cân nhắc vận mệnh gia tộc, nên yêu cầu xem Lôi Tiên lệnh bài trước khi quyết định. Vương Lâm lấy ngọc giản của Lôi Đạo Tử ra, lôi uy trên đó khiến Thiên Quỳ Tử tin thân phận sứ giả của hắn. Thiên gia giao một nửa Thăng Tiên quả nhưng chỉ hứa sẽ phụ thuộc khi Vương Lâm đạt Âm Dương Hư Thực, khiến Thiên Quỳ Tử sau đó sinh lòng hối hận. Rời Thiên Huyễn Tinh, Vương Lâm tiếp tục dùng danh nghĩa Sứ giả Lôi Tiên Điện quét qua La Thiên bắc vực để thu gom Thăng Tiên quả."},{"chuong":666,"tieuDe":"Bài Tiết","tomTat":"Vương Lâm dùng thân phận Sứ giả Lôi Tiên Điện thu gom lượng lớn Thăng Tiên quả nhưng từ chối nhận gia tộc phụ thuộc. Sau nửa năm, hắn cưỡi Lôi Thú tới Vân Hà Tinh, trên đường tra xét hồn phách lão giả trong Tôn Hồn Phiên để ghi nhớ thần thông chạy trốn. Khi xuyên qua sương mù, hắn bị xúc tu Vọng Nguyệt tập kích, mất Thất Tinh kiếm trận và nhận ra Vọng Nguyệt đang chuyển sang trạng thái công kích. Vương Lâm luyện Thăng Tiên quả thành hồng vụ để gây tê xúc tu, cấy lạc ấn vào phần lớn gốc xúc tu, đồng thời cứu Lôi Thú khỏi vòng vây rồi thu nó lại thành Xạ Thần Xa. Bên trong Vân Hà Tinh, Tham Lang xuất hiện trong nơi bài tiết của Vọng Nguyệt, bị đại đỉnh và xúc tu vây khốn. Khi Thăng Tiên quả đã cạn, Vương Lâm không rời đi mà xuống lòng đất tìm Kim Viêm quáng mạch, nhưng phát hiện tiên lực bất thường nên tạm dừng hấp thu xương để truy xét nguy cơ."},{"chuong":667,"tieuDe":"Tiểu Bảo Vật Của Tham Lang","tomTat":"Vương Lâm men theo xương của Vọng Nguyệt và phát hiện một khe lớn gần chặt đứt bộ xương, dấu vết mà trước kia không tồn tại. Tại khe này, hắn tìm thấy khối sơn thạch cực lớn của Tham Lang đã bị Kim Viêm quáng mạch đồng hóa, nên dùng một tia kiếm khí của Lăng Thiên Hậu để cắt lấy phần có thể tách ra. Khi sắp thành công, một con Vọng Nguyệt nhỏ phục kích từ bùn đất, buộc Vương Lâm dùng Định thân thuật rồi nhanh chóng bỏ chạy. Từ biến hóa bất thường của thân thể Vọng Nguyệt, hắn suy đoán Tham Lang có thể đã động tới thứ nguy hiểm hơn, đặc biệt là Nguyệt Hoa mang kịch độc và nguy cơ tự bạo. Sau khi tìm kiếm mà không gặp thêm cá thể nào, Vương Lâm chuyển hướng tới nơi bài tiết hấp thu để lần theo vật hoặc người bị nuốt vào."},{"chuong":668,"tieuDe":"Rút Xương Cốt Của Vọng Nguyệt","tomTat":"Vương Lâm thận trọng tới gần nơi bài tiết hấp thu của Vọng Nguyệt và phát hiện thần niệm cầu cứu của Tham Lang. Chương hé lộ Tham Lang vì cảm ứng trọng bảo mà lẻn vào Vân Hà Tinh, đào Kim Viêm quáng mạch rồi chạm tới Nguyệt Hoa, cuối cùng bị nuốt vào nơi bài tiết và mắc kẹt gần trăm năm nhờ đại đỉnh thần bí. Vương Lâm nhận ra cứu Tham Lang là tự đưa mình vào hiểm cảnh nên dứt khoát bỏ đi, không tham pháp bảo. Hắn quay lại chỗ xương bị sơn thạch kẹt, gọi Tiên Vệ hộ vệ rồi phá toàn bộ lạc ấn trong chất lỏng Thăng Tiên quả đã cấy vào xúc tu. Lực lượng kỳ dị lan khắp Vân Hà Tinh, khiến xúc tu mất tính công kích trong trạng thái hưng phấn. Nắm thời cơ, Vương Lâm thi triển Đạo hóa Hoàng Tuyền đệ tam thức, dùng Hoàng Tuyền lực rút xương cốt Vọng Nguyệt khiến toàn bộ tinh cầu rung chuyển và vang lên tiếng rống tang thương."},{"chuong":669,"tieuDe":"Vọng Nguyệt Thức Tỉnh","tomTat":"Trong lòng Vân Hà Tinh, Vương Lâm dùng Hoàng Tuyền lực tác động lên hai đầu xương cốt Vọng Nguyệt, khiến bộ xương rung động như vật sống và làm toàn bộ tinh cầu chấn động. Do đã hấp thu nhiều Thăng Tiên quả, đau đớn của Vọng Nguyệt bị biến thành hưng phấn kỳ dị, nhưng thân thể nó vẫn bắt đầu thức tỉnh: xúc tu phun hồng vụ, bùn đất nứt vỡ và khí tức hung thú cổ xưa lan ra. Cảm nhận nguy cơ tăng nhanh, Vương Lâm liều mạng kéo nửa đoạn xương sống bên trái ra khỏi lòng đất bằng toàn bộ tiên lực và thân thể. Hắn triệu Tiên Vệ cảnh giới Âm Hư kéo nửa đoạn xương sống còn lại, khiến hai nửa xương khổng lồ lần lượt được rút lên mặt đất. Vì xương sống quá lớn không thể cất vào túi trữ vật, Vương Lâm phải kéo đi trực tiếp trong lúc xúc tu Vọng Nguyệt quấn giữ. Để phá thế cản, hắn cắn răng lấy Cấm Phiên, pháp bảo đã theo mình hơn chín trăm năm và có chút linh trí."},{"chuong":670,"tieuDe":"Trốn Trốn Trốn!","tomTat":"Cấm Phiên tan vỡ, linh tính vì Vương Lâm mà sinh cũng vì hắn mà diệt, hóa thành cấm chế đánh vào xúc tu của Vọng Nguyệt để mở ra một khoảnh khắc thoát thân. Vọng Nguyệt thức tỉnh khiến Vân Hà Tinh rung chuyển, mặt đất nứt như miệng khổng lồ, tiên lực của Vương Lâm tán loạn nhưng hắn vẫn cùng Tiên Vệ khiêng xương cốt lao vào tầng sương mù. Khi khe nứt truy tới, Vương Lâm gọi Thất Tinh Kiếm Trận trở về rồi lần lượt cho Tử Thử kiếm và sáu kiếm còn lại cùng tà hồn tự bạo, không làm Vọng Nguyệt bị thương đáng kể nhưng khiến nó chậm lại đúng lúc. Sự tan vỡ của Vân Hà Tinh được hé lộ không phải tinh cầu nổ tung từ bên trong, mà là thân thể Vọng Nguyệt xoay mình ngẩng đầu khiến các lục địa bám trên người nó vỡ thành bụi phấn. Vọng Nguyệt phát ra tiếng nói Cổ Thần và thi triển kỹ thuật phá nát của Bát Tinh Cổ Thần, làm bầu trời nứt vỡ, khiến Vương Lâm nghi hoặc vì ký ức Đồ Ti chưa từng ghi nhận khả năng này. Trong sát cơ, Vương Lâm dùng tiếng nói Cổ Thần truyền thừa từ Đồ Ti đáp lại, làm khe nứt tạm ngừng rồi tiếp tục bỏ chạy. Cùng lúc đó, Tham Lang nhân biến động thoát khỏi chỗ bài tiết và hấp thu của Vọng Nguyệt, mang theo Cự Đỉnh, vừa sợ hãi vừa hưng phấn vì cuối cùng nhìn thấy cơ hội rời khỏi nơi tanh tưởi sau trăm năm."},{"chuong":671,"tieuDe":"Trốn Trốn Trốn!","tomTat":"Cấm Phiên của Vương Lâm tự hủy, hóa thành cấm chế màu đen có linh tính để làm các xúc tu của Vọng Nguyệt chậm lại, giúp hắn và Tiên Vệ mang xương cốt Vọng Nguyệt lao về phía tầng sương mù. Vọng Nguyệt thức tỉnh dữ dội, mặt đất Vân Hà Tinh lộ rõ là thân thể của nó, lục địa bám trên thân vỡ vụn còn tiếng rống khiến Vương Lâm và Tiên Vệ bị chấn động. Khi khe nứt truy sát áp sát, Vương Lâm gọi Thất Tinh Kiếm Trận trở về rồi cho Tử Thử kiếm cùng sáu kiếm thể còn lại và tà hồn tự bạo, đổi lấy khoảnh khắc đủ để tiếp tục thoát thân. Sau đó Vọng Nguyệt phát ra tiếng nói Cổ Thần bất thường, khiến Vương Lâm nhận ra nguy cơ từ kỹ thuật phá nát cấp Bát Tinh Cổ Thần và phải dùng tiếng nói Cổ Thần truyền thừa từ Đồ Ti để tạm ngăn khe nứt lan rộng. Trong lúc biến động toàn thân Vọng Nguyệt diễn ra, khu vực bài tiết và hấp thu xuất hiện vết nứt, Tham Lang mang Cự Đỉnh phóng ra với hy vọng thoát khỏi nơi tanh tưởi đã giam giữ hắn lâu ngày."},{"chuong":672,"tieuDe":"Vọng Nguyệt Phẫn Nộ Như Một Chỉ Của Cổ Thần","tomTat":"Tham Lang sau trăm năm bị nhốt trong bộ phận bài tiết của Vọng Nguyệt dốc sức lao tới khe nứt để thoát, nhưng Vương Lâm ném trả nửa đoạn xương Vọng Nguyệt khiến đường thoát của hắn lại bị cản. Khi hiệu lực Thăng Tiên Quả tiêu tán, Vọng Nguyệt nhận ra đó là xương của mình, cơn đau và phẫn nộ bùng phát đúng như ký ức Cổ Thần Đồ Ti từng mô tả. Vương Lâm cùng Tiên Vệ mang nửa xương còn lại lao vào tinh không bằng Tinh La Bàn, đồng thời thử để Thiên Nghịch hấp thụ xương nhưng chưa thành. Vọng Nguyệt truy sát, phun ra ngôn ngữ Cổ Thần và thả đàn Vọng Nguyệt nhỏ; Vương Lâm uống hai giọt tiên tửu để thi triển Định Thân Thuật, tạm khóa đám hung thú nhỏ và ngăn Tham Lang đổi vị trí với mình. Tham Lang kích phát Cự Đỉnh đổi vị trí, hi sinh thọ nguyên để phóng lớn pháp bảo rồi đau lòng bỏ lại khi Vọng Nguyệt bị khí tức của đỉnh hấp dẫn. Cuối cùng Tham Lang lấy bình phong Sơn Hà Đồ chống đỡ, nhưng Vọng Nguyệt huyễn hóa một chỉ Cổ Thần phá tan bình phong, khiến hắn phun máu nguyên thần và tiếp tục bị uy năng ấy ép tới."},{"chuong":673,"tieuDe":"Chạy Đằng Trời!","tomTat":"Vương Lâm nhận ra bình phong trong tinh không mang thần thông Sơn Hà Đồ, liền lợi dụng lúc Cổ Thần Chỉ đang truy đuổi Tham Lang để lao tới đoạt bảo. Hắn thi triển Định Thân Thuật lên Tham Lang, khiến đối phương khựng lại và kéo sự chú ý của ngón tay Cổ Thần, rồi thu bình phong vào túi trữ vật. Tham Lang đội Tôn Tiên Đế Quan, dùng vương miện kim quang có năm hạt châu ngũ hành và linh hồn đế vương để chịu một chỉ, nhưng vẫn bị đánh bay mất tung tích, còn vương miện rơi vào tinh không. Cổ Thần Chỉ sau đó chuyển mục tiêu sang Vương Lâm; Sinh Mệnh Lạc Ấn, Đệ Nhị Tiên Vệ và kiếm khí Lăng Thiên Hậu lần lượt bị phá, cuối cùng nhục thân Vương Lâm tan thành bụi. Một chỉ vô tình phá lớp màng giam nguyên thần, khiến nguyên thần hắn hóa thành thái cổ Lôi Long, phóng lôi cầu cản địch rồi cuốn túi trữ vật, Tiên Vệ và xương Vọng Nguyệt bỏ chạy. Trên đường đào thoát, Vương Lâm dùng thần thức thu thêm vương miện của Tham Lang, tự tổng kết mình mất Thất Tinh Kiếm Trận, Cấm Phiên, kiếm khí và nhục thân nhưng đổi lại đoạt được nhiều bảo vật. Khi Cổ Thần Chỉ tiêu tán, Vọng Nguyệt vẫn do dự nhìn cự đỉnh trên xúc tua rồi tiếp tục truy sát, buộc nguyên thần Vương Lâm dung hợp vào Tinh La Bàn để điên cuồng bỏ chạy."},{"chuong":674,"tieuDe":"Lôi Ngục","tomTat":"Vương Lâm nhập nguyên thần vào Tinh La Bàn, liều mạng chạy khỏi La Thiên Bắc Vực trong tình trạng bị trọng thương, cuối cùng thoát chết khi Vọng Nguyệt dừng lại trước ranh giới Nam-Bắc Vực vì một nỗi kiêng kỵ mơ hồ. Dị thú khổng lồ sau đó quay về gần Ngũ Đại Chủ Tinh, thu cự đỉnh và xúc tua vào thân thể rồi chìm vào giấc ngủ, khiến tu sĩ Bắc Vực hoảng sợ vì khoảng cách quá gần. Cùng lúc, Tham Lang rơi xuống một tinh cầu nguyên thủy, thân thể gần như tan nát nhưng vẫn sống sót; hắn phát hiện phần lớn lạc ấn khống chế trong cơ thể đã bị một chỉ Cổ Thần phá hủy, chỉ còn lạc ấn của Thiên Vận Tử, nên lẩn xuống lòng đất chờ ngày phục hồi. Ở La Thiên Nam Vực, bản năng nguyên thần Lôi Long dẫn Vương Lâm tới một tiểu tinh cầu bị tầng đá che giấu, nơi tràn ngập lôi điện tiên thiên và sinh cơ nồng đậm, rất thích hợp để hắn chữa thương. Tiên Vệ e dè trước thiên lôi nên được để lại bên ngoài hộ pháp, còn Vương Lâm đặt nửa khúc xương Vọng Nguyệt xuống mặt đất rồi ngồi giữa Lôi Ngục hấp thu lôi lực suốt mười năm. Khi nguyên thần hoàn toàn khôi phục, hắn phá vỡ lôi cầu bao quanh, hút lôi pháp vào cơ thể, toàn thân như khoác giáp sấm. Sau đó Vương Lâm vận dụng bí thuật trong Cổ Thần Quyết từ ký ức Đồ Ti, dẫn lôi điện trong Lôi Trì ngưng tụ xương tay, khung xương rồi rút lôi lực toàn tinh cầu để tiếp tục tái tạo thân thể mới."},{"chuong":675,"tieuDe":"Thiên Nghịch Hấp Thu Và Bảo Vật Của Tham Lang!","tomTat":"Sau một giáp hấp thu lôi quang và sinh cơ trên tinh cầu lôi quang, Vương Lâm phá kén bước ra với thân thể mới, máu thịt ẩn chứa sức mạnh sấm sét tương hỗ với nguyên thần lôi quang. Hắn bố trí hộ pháp bằng Tôn Hồn Phiên, ba chủ hồn và Đệ Tứ Hồn rồi cẩn thận lấy Thiên Nghịch Châu từ mi tâm ra, đặt lên dãy núi do xương Vọng Nguyệt hóa thành để hấp thu Kim Viên Quáng. Trong lúc chờ Thiên Nghịch hấp thu chậm, Vương Lâm kiểm tra những bảo vật đoạt từ Tham Lang, dùng núi đá tiên giới để rút Sơn Hồn và hiểu thêm giá trị cảm ngộ thần thông rút linh hồn linh vật của Đệ Nhị Bộ. Hắn tiếp tục xem xét bình phong Sơn Hà Đồ, nhận ra đó chỉ là bản in lại của Sơn Hà Thiên Đạo Đồ, bèn lưu lạc ấn và đưa vào nguyên thần tế luyện. Với Vương Miện, hắn phát hiện năm hạt châu ngũ hành có linh tính, nhớ tới Hồng Điệp rồi thử dùng đóa hồng lam, khiến đóa hồng tan thành lam quang dung nhập vào pháp bảo và để lại bóng người múa kiếm mơ hồ. Ba tháng sau, Kim Viên Quáng bị hấp thu hết, thuộc tính kim của Thiên Nghịch viên mãn; Vương Lâm nhỏ máu dung hợp thần thức lạc ấn lên hạt châu, khiến một phù văn cổ xưa tang thương hiện ra trong tâm thần và được hắn vẽ ra trước người."},{"chuong":676,"tieuDe":"Thiên Nghịch Viên Mãn","tomTat":"Khi khí tức tang thương tràn ngập tinh cầu lôi quang, Vương Lâm đưa phù văn vào Hạt Châu Thiên Nghịch, khiến tử quang mục nát bùng phát và ăn mòn mọi thứ xung quanh. Tiên Vệ cùng tam đại chủ hồn trong Tôn Hồn Phiên cũng bị tử quang ảnh hưởng, buộc hắn phải lập tức thu hồi để tránh chúng tan rã. Tử quang lan khắp tinh cầu, phá hủy mặt đất và tầng đá ngoài, đồng thời hình thành cấm chế mạnh đến mức sinh linh không thể tiến vào, như cắt đứt khu vực này khỏi La Thiên Tinh Vực. Sau khi lực ngũ hành tích lũy trong Thiên Nghịch bị phóng xuất hơn phân nửa, một cánh cửa màu tím khổng lồ hiện ra giữa thiên địa, khiến Vương Lâm sinh nỗi sợ từ linh hồn. Hắn nhớ tới thời thiếu niên ở Hằng Nhạc Phái nhưng vẫn dùng đạo niệm bất khuất để chống lại nỗi sợ, vì phải bảo vệ hồn phách của mình và Uyển Nhi trong Thiên Nghịch. Khi tử quang ngoài cửa hóa thành cánh tay khổng lồ vẫy gọi, Vương Lâm không bước vào mà ném xương Vọng Nguyệt để thử; cánh tay chỉ sờ nhẹ đã làm xương tan vỡ và khiến trời đất, tinh không cùng khu vực quanh tinh cầu bị xé nát."},{"chuong":677,"tieuDe":"Thiên Nghịch Triệu Tập","tomTat":"Cánh tay khổng lồ sau cánh cửa thiên địa tiếp tục vẫy gọi Vương Lâm, khiến hắn nhận ra cái sờ nhẹ của nó là một loại quy tắc cực mạnh, vượt xa cảm nhận thông thường của hắn. Sau khi cánh tay và cánh cửa biến mất, tử quang co lại thành Thiên Nghịch Châu rơi về tay Vương Lâm, nhưng bề mặt hạt châu đã không còn ngũ hành lực. Hắn dùng thần thức kiểm tra, thấy nguyên anh Lý Mộ Uyển, Vương Bình và hồn phách Thanh Nghi vẫn còn trong châu, thậm chí linh động hơn trước, rồi suy đoán về những chủ nhân Thiên Nghịch từng khiến ngũ hành viên mãn và có thể đã tiến vào cánh cửa. Vì Lôi Quang tinh cầu đã thành phế tích, Vương Lâm quyết định đi sâu vào tầng đá vụn tìm nguồn lôi quang để tu luyện Lôi Nguyên Thuật. Hắn lấy Xạ Thần Xa hóa thành Lôi Thú; Lôi Thú cảm nhận hắn như một đạo sấm sét nên vừa kinh ngạc vừa thân thiết, chở hắn xuyên qua khu vực đá vụn ngày càng dày. Cuối cùng Vương Lâm phát hiện phía trước không phải tinh cầu mà là vùng không gian đầy vô số Lôi Trì khổng lồ, sấm sét cuồng bạo như địa ngục lôi điện. Hắn thả khôi lỗi Tiên Vệ hộ pháp, bước vào rìa Lôi Trì tới cực hạn rồi khoanh chân thổ nạp, trong khi Lôi Thú cũng hấp thu lôi điện bên ngoài."},{"chuong":678,"tieuDe":"Thiên Nghịch Kinh Biến","tomTat":"Một người đàn ông tóc đen cưỡi Lôi Thú khoác giáp đen bay trong tinh không về phía tầng đá vụn Nam Vực La Thiên, định vào Lôi Ngục hấp thụ nguyên lực trước khi Lôi Tiên Giới mở ra. Hắn nhắc tới truyền thuyết hạt châu Thiên Nghịch lần đầu xuất hiện tại tầng đá vụn này, từ đó sinh ra dị biến Lôi Đình và biến nơi đây thành Lôi Ngục. Trong Lôi Trì, Vương Lâm đọc hiểu Lôi Nguyên Thuật, dùng thủ ấn dẫn Lôi Đình nhập thể và chuyển hóa được một tia nguyên lực pha tạp. Khi hắn định đưa tia nguyên lực vào nguyên thần luyện hóa, nó mất khống chế lao tới mi tâm nguyên thần và dung nhập vào Thiên Nghịch, khiến nguyên thần cùng thân thể chấn động mạnh. Thiên Nghịch sau đó tự bay ra khỏi mi tâm Vương Lâm, làm Lôi Trì bạo loạn, khiến Tiên Vệ và Lôi Thú phải lùi xa, đồng thời hút vô số Lôi Long từ bốn phương tám hướng. Khi hạt châu hấp thu lôi điện, tử quang, cấm chế kỳ dị và cánh cửa lớn từng xuất hiện trước đó lại hiện ra giữa trời đất. Chương khép lại bằng việc xác lập rằng Vương Lâm vô ý đưa Thiên Nghịch trở về nơi nó từng lần đầu xuất hiện, và cảm giác dẫn hắn tới đây có liên quan sâu tới chính Thiên Nghịch."},{"chuong":679,"tieuDe":"Tầm Đạo Giả, Vong Sinh Tri Tử, Hám Nhĩ…","tomTat":"Sau khi ngũ hành viên mãn, Thiên Nghịch biến hóa, nhận chủ Vương Lâm và được hắn hấp thu vào nguyên thần. Cánh cửa Thiên Địa lại hiện ra giữa Lôi Trì, tử quang phủ khắp, còn cánh tay khổng lồ bên ngoài cửa bị vô số lôi điện màu tím quấn lấy trấn áp. Vương Lâm nhận ra đây là cơ hội hiếm có nên giữ sẵn đường lui rồi mạo hiểm lao tới khe cửa; khi cửa mở, thân thể hắn dừng ngoài khe hở còn tâm thần bị hút vào không gian Thiên Nghịch. Trong không gian ấy, hắn chứng kiến vật sáng bành trướng thành tinh cầu có đại lục, sông biển và linh khí, rồi lại thoái hóa về vật sáng như thời gian đảo ngược, khiến tâm thần dần chìm vào trạng thái quên hết. Hắn tiếp tục quan sát sinh diệt, theo bản năng truy tìm nguồn lực lượng thần bí và dấu chân của Đạo. Sau đó, Vương Lâm gặp một tinh cầu ấm áp cùng hai tinh cầu nhỏ mang khí tức quyến luyến; khi hắn chạm vào hư vô, ba tinh cầu hóa thành ba luồng hào quang nhập vào đầu hắn. Từ đó hắn dừng truy tìm, bản thân hóa thành vật sáng rồi bành trướng thành một tinh cầu có núi sông, biển cả và sinh hoạt phàm tục. Trên tinh cầu này có một nam một nữ ở phía bắc và một cô gái áo trắng ở phía nam; qua vô số năm tháng, tinh cầu biến đổi nhưng ba người ấy là điều duy nhất không biến mất."},{"chuong":680,"tieuDe":"Thấy Được Bước Thứ Ba","tomTat":"Vương Lâm tỉnh khỏi cảnh giới kỳ dị trong Thiên Nghịch sau khi chứng kiến biến hóa sinh tử, nhân quả và tự hỏi đó có phải là Đạo. Qua hình ảnh Lý Mộ Uyển, Vương Bình và Thanh Nghi, hắn nhận ra đạo sinh tử luân hồi cùng đạo nhân quả của mình, rồi bị một lực lượng mạnh đẩy nguyên thần trở lại bên ngoài cánh cửa lớn giữa lôi đình và tử quang. Khi cánh cửa khép lại, tử quang co rút thành Thiên Nghịch Châu, lạc ấn ngũ hành trên châu biến mất và thay bằng âm dương ngày đêm chia đôi trước khi dung nhập mi tâm hắn. Vương Lâm hiểu cơ duyên lần này không trực tiếp tăng tu vi nhưng làm tâm cảnh thăng hoa, quý đến mức ngay cả Thiên Vận Tử cũng có thể đánh đổi tất cả để cầu được; hắn đã nhìn thấy khí tức bước thứ ba. Sau đó, một người đàn ông tóc đen cưỡi Lôi Thú mặc áo giáp tiến vào tầng đá vụn, nhận ra lôi quang và khí tức nơi Lôi Ngục biến động khác thường. Người này vốn có tu vi Dương Thực, quen đến Lôi Trì tu luyện Lôi Nguyên Thuật, nhưng khi thấy Vương Lâm lơ lửng bên trên Lôi Trì đã rút nhỏ gần một nửa, hắn lập tức kinh hãi. Vương Lâm mở mắt, ánh mắt còn lưu tàn ảnh cảm ngộ bước thứ ba khiến đối phương bị chấn nhiếp, tim máu và nguyên lực đều rối loạn như sắp sụp đổ."},{"chuong":681,"tieuDe":"Người Thứ Nhất Dựa Vào","tomTat":"Vương Lâm tỉnh khỏi cảnh mộng tầm đạo do Thiên Nghịch mở khe hở, nhưng dư uy trong ánh mắt vẫn khiến người đàn ông tóc đen và tọa kỵ Lôi Thú bị áp chế đến mức sinh tử mong manh. Sau khi thoát khỏi áp lực ấy, người đàn ông tóc đen nhận định cảnh tượng vừa rồi giống Đạo Yểm trong truyền thuyết La Thiên, từ sợ hãi chuyển sang sùng kính. Vương Lâm tự nhận cơ duyên lần này đã cho hắn thấy con đường tới bước thứ ba Tu Đạo, khiến tâm tính, linh hồn và ý cảnh có biến hóa lớn. Người đàn ông tóc đen tự xưng là Thân Công Hổ, Nhị cấp sứ giả Lôi Tiên Điện, người Thân Công tộc nam vực La Thiên, tu sĩ Dương Thật, rồi quỳ xin dựa vào Vương Lâm. Khi bị từ chối, hắn rút Đạo Hồn chứa ý cảnh và đạo niệm để làm bảo chứng nương tựa ngàn năm, và Vương Lâm cuối cùng thu Đạo Hồn vào nguyên thần. Thân Công Hổ sau đó giải thích mình đến Lôi Trì để tu luyện trước khi Lôi Tiên Giới mở ra sau mười năm, đồng thời nói về Lôi Đỉnh, giới hạn tu vi vào giới và bí pháp Lôi Tiên Điện. Vương Lâm bộc lộ mình không phải người La Thiên Tinh Vực, nắm được giá trị của Lôi Tiên Giới đối với việc tìm tiên ngọc tu luyện, rồi cho phép Thân Công Hổ ở lại Lôi Trì nhưng không được quấy rầy mình."},{"chuong":682,"tieuDe":"Lôi Nguyên Ngưng Tụ","tomTat":"Thân Công Hổ được Vương Lâm cho ở lại Lôi Trì, bề ngoài cảm kích nhưng thực chất đạo tâm đã bị ánh mắt của Vương Lâm làm cho khiếp sợ, lại vì đã giao đạo hồn nên trong tiềm thức chịu khuất phục. Vương Lâm tiến sâu khoảng trăm bước vào Lôi Trì rồi khoanh chân tu luyện, khiến Thân Công Hổ càng sùng kính vì bản thân hắn khó chịu nổi khoảng cách ấy. Lôi Thú của Thân Công Hổ bị Lôi Thú sừng bạc của Vương Lâm áp chế, còn Tiên Vệ ngồi trên đá vụn canh chừng. Vương Lâm dùng Lôi Nguyên Thuật hấp thụ lôi đình, rút nguyên lực pha tạp để luyện hóa vào nguyên thần, đồng thời chương giải thích nguyên lực của hắn đã xuống rất thấp sau trận với Lôi Đạo Tử do chưa có Vấn Đỉnh Chi Tinh. Trong hai năm tu luyện, hắn tăng dần lượng lôi đình hấp thụ, còn Thân Công Hổ cũng chăm chỉ chữa thương và quan sát. Vương Lâm nhận ra công pháp của Thân Công Hổ tuy giống Lôi Nguyên Thuật nhưng hiệu suất chuyển hóa cao hơn nhiều, từ đó hiểu thêm khác biệt giữa các cảnh giới bước tu đạo thứ hai. Sau khi ghi nhớ cảm ngộ bước thứ ba và có chút thu hoạch, hắn đứng dậy, xác định lôi đình gần trung tâm Lôi Trì chứa nguyên lực vượt xa vùng ngoài, rồi cẩn thận bước sâu hơn, dẫn động vô số lôi đình lao tới."},{"chuong":683,"tieuDe":"Quy Luật Của Sấm Sét","tomTat":"Vương Lâm dùng thân thể do lôi đình biến thành và nguyên thần mang lôi uy để thử tiến vào Lôi Trì, nhưng chỉ đi được mười bước thì cảm thấy nguyên thần không thể chịu nổi uy thế nơi đây. Thân Công Hổ chứng kiến cảnh đó thì thất vọng, cho rằng tiền bối mà mình sùng kính cũng chỉ đạt mức hắn có thể chạm tới khi vào Khuy Niết sơ kỳ. Vương Lâm không tiếp tục cưỡng ép mà nhìn sâu vào Lôi Trì, dần quên hết ngoại giới và tiến vào trạng thái cảm ngộ tương tự khi từng nhìn vào không gian Nghịch Thiên. Từ trong vô số lôi đình, hắn nhận ra các tia sáng ẩn hiện và mỗi bước tiếp theo đều hạ đúng nơi lôi quang xuất hiện, khiến Thân Công Hổ kinh hãi rồi cuồng nhiệt trở lại. Lôi Thú mặc giáp của Thân Công Hổ cảm nhận sâu hơn rằng Vương Lâm không được Lôi Trì nghênh đón, mà như đang đạp lên chính Lôi Trì, nên sinh ra kính sợ từ linh hồn. Lôi Thú sừng bạc của Vương Lâm cũng đứng bật dậy vì chấn động. Khi tỉnh khỏi cảm ngộ, Vương Lâm hiểu rằng nhận thức mới về sấm sét có liên hệ tới bước thứ ba và còn quan trọng hơn tiên thuật, pháp bảo đối với hắn."},{"chuong":684,"tieuDe":"Nghi Ngờ Bên Tai","tomTat":"Vương Lâm tỉnh lại ở vòng trong Lôi Trì, phát hiện nơi này có lôi đình dày đặc và thiên địa nguyên lực mạnh hơn hẳn bên ngoài, nhưng mỗi lần thổ nạp đều khiến thân thể cùng nguyên thần bị tê liệt, vận chuyển chậm chạp. Trong lúc Thân Công Hổ còn đang kích động vì những gì đã chứng kiến, Chiến Không Liệt thuộc Chiến gia cưỡi kiếm gỗ màu tím tiến vào, lập tức khiến bầu không khí trở nên căng thẳng. Chiến Không Liệt nhìn thấy Vương Lâm ở vị trí sâu trong Lôi Trì, lại thấy Lôi Thú sừng bạc và Tiên Vệ con rối bên cạnh, nên nghi ngờ Vương Lâm có pháp bảo cực mạnh, ẩn giấu tu vi hoặc liên quan tới Lôi Tiên Điện. Thân Công Hổ dựa vào sự hiện diện của Vương Lâm để uy hiếp Chiến Không Liệt rời đi trong ba nhịp thở, còn Chiến Không Liệt vừa thăm dò vừa chuẩn bị lôi pháp và kiếm khí để giao chiến. Vương Lâm hiểu mình chưa đủ sức trực tiếp đối đầu với hai người, nên dùng lời nói biến trận chiến thành khảo nghiệm dành cho Thân Công Hổ, đồng thời tuyên bố nếu Thân Công Hổ thất bại sẽ trả lại đạo hồn. Thân Công Hổ vì thế chiến ý bừng lên và công khai gọi Vương Lâm là Tôn chủ, khiến Chiến Không Liệt chấn động mạnh trước quan hệ thần phục bất ngờ này."},{"chuong":685,"tieuDe":"Lão Tử Rất Lợi Hại Đấy","tomTat":"Trong Lôi Trì, Chiến Không Liệt suy xét cách Thân Công Hổ gọi Vương Lâm là Tôn Chủ và dần nghi rằng Vương Lâm không đơn giản dựa vào pháp bảo, mà có thể là tiền bối ẩn tu che giấu tu vi. Thân Công Hổ vì muốn thể hiện trước mặt Vương Lâm đã nuốt đan dược phát hồng quang, cưỡng ép áp chế thương thế rồi dùng Dẫn lôi thuật giao chiến với Chiến Không Liệt. Hai tu sĩ bước thứ hai va chạm bằng lôi quang và kiếm khí, tạo chấn động lớn khiến cả hai đều bị đẩy lui. Vương Lâm quan sát trận đấu, dựa vào kinh nghiệm từng thấy cấp độ bước thứ ba và cảm nhận quy luật sấm sét trong Lôi Trì để chỉ ra Dẫn lôi thuật có lôi uy nhưng thiếu lôi hồn. Hắn thu một đạo lôi quang vào lòng bàn tay, khiến nó tiêu tán chỉ còn ánh sáng thoáng qua, mượn đó gợi ý cho Thân Công Hổ về căn nguyên của sấm sét. Thân Công Hổ nhờ vậy như phá được tầng ngăn cách trong nhận thức và càng sùng bái Vương Lâm. Chiến Không Liệt cũng càng tin Vương Lâm là cao nhân, cung kính nhận lỗi rồi nói mình đã nhận thư triệu tập của Lôi Tiên Điện, sau này sẽ cùng Thân Công Hổ làm sứ giả, rồi rời khỏi nơi này."},{"chuong":686,"tieuDe":"Lão Tử Rất Lợi Hại Đấy","tomTat":"Chiến Không Liệt từ cách Thân Công Hổ gọi Vương Lâm là Tôn Chủ mà sinh nghi, cho rằng Vương Lâm có thể là tiền bối ẩn tu chứ không chỉ dựa pháp bảo để vào vòng trong Lôi Trì. Thân Công Hổ nuốt đan dược của Lôi Tiên Điện, cưỡng ép khôi phục khí tức rồi dùng Dẫn lôi thuật giao thủ với Chiến Không Liệt, nhưng bị Vương Lâm nhìn ra thần thông có lôi uy mà thiếu lôi hồn và căn nguyên. Vương Lâm biểu diễn lôi quang quy về căn nguyên khiến Thân Công Hổ ngộ đạo, còn Chiến Không Liệt cúi đầu nhận hắn là tiền bối, nói rõ chuyện thư triệu tập và cơ chế sứ giả Lôi Tiên Điện rồi rời đi. Sau tổng cộng mười năm tu luyện trong Lôi Trì, Vương Lâm nhờ Lôi nguyên thuật đạt mức nguyên lực ổn định, nguyên thần bão hòa nhưng không thể hấp thụ thêm vì tu vi chưa đủ, nên cưỡi Lôi Thú sừng bạc rời đi cùng Tiên Vệ. Trên đường, hắn xác định hai mươi năm sau phải tới Lôi Tiên Giới, trước đó cần nâng tu vi, tìm hiểu Thiên Nghịch Châu, chỉnh lý thần thông và kiếm một tu chân tinh thuộc về mình tại La Thiên Tinh Vực. Khi tới một tinh cầu gợi nhớ Chu Tước Tinh, Hứa Lập Quốc trong tiên kiếm khoe đã nuốt kiếm ý viễn cổ nhưng lập tức bị Vương Lâm trấn áp. Vương Lâm đặt chân lên Thanh Linh Tinh, chọn Hoành Vân Phong làm nơi dừng chân, đúng lúc gia chủ Trương gia là Trương Tân Hải lên núi chuẩn bị tọa hóa và kinh sợ vì thấy hắn bằng mắt thường trong khi thần thức không phát hiện được."},{"chuong":687,"tieuDe":"Tu Chân Tinh Của Ta","tomTat":"Vương Lâm hiện thân trên Hoành Vân Sơn Phong và chỉ bằng khí tức đã khiến Trương Tân Hải nhận ra chênh lệch lớn giữa hai người. Hắn xua tan tử khí tích tụ qua vô số năm trên ngọn núi, dùng linh quyết thiêu đốt linh lực để kéo dài tuổi thọ cho Trương Tân Hải thêm mười năm, đồng thời nhớ tới tiếc nuối về Lý Mộ Uyển trong Thiên Nghịch Châu. Sau đó Vương Lâm giao Trương Tân Hải nhiệm vụ trong mười năm phải thu thập oán khí phàm nhân càng nhiều càng tốt, đổi lại bảo đảm hương hỏa Trương gia khi hắn còn ở Thanh Linh Tinh. Vương Lâm cắm Tôn Hồn Phiên, thả hồn phách và ba đại chủ hồn bao phủ Hoành Vân Sơn Phong, mở động phủ rồi truyền thần niệm khắp tinh cầu tuyên bố Thanh Linh Tinh là tu chân tinh của mình và ngọn núi là cấm địa. Trong năm năm sau, Trương gia cùng các gia tộc tu chân bôn ba thu oán khí nhưng mới đạt chưa đến bốn phần. Còn Vương Lâm ở trên đỉnh núi tế luyện Sơn Hà Đồ, sơn thạch tiên giới, nghiên cứu vương miện hoa hồng màu lam của Hồng Điệp và nhận ra Côn Cực Tiên là pháp bảo duy nhất của hắn ẩn chứa phương hướng bước thứ ba."},{"chuong":688,"tieuDe":"Pháp Khí Đại Diện Cho Nhân Quả Ý Cảnh","tomTat":"Vương Lâm suy xét Côn Cực Tiên và đạo nhân quả, nhận ra bản thể có thể xem là nhân, nguyên thần là quả, từ đó tìm được cách dùng pháp bảo này làm vật đại diện cho nhân quả ý cảnh. Ý cảnh của hắn đang chuyển từ sinh tử luân hồi sang nhân quả, chưa thể thực chất hóa hoàn toàn như trước kia nhưng đã mở ra phương hướng cho bước thứ ba. Vì chuẩn bị tiến vào Lôi Chi Tiên Giới, hắn ở lại Hoành Vân Phong tế luyện Côn Cực Tiên suốt ba năm, trong khi danh hiệu lão tổ Thanh Linh Tinh ngày càng lan rộng và màn sương đen quanh núi trở thành vùng cấm. Hứa Lập Quốc phá được phong ấn túi trữ vật, liên tục kêu gào đòi đổi vai chủ tớ với Vương Lâm, rồi khi được thả ra liền hóa thành đại kiếm mang viễn cổ kiếm ý lao tới. Vương Lâm không tự động thủ, chỉ để Côn Cực Tiên bay lên, tỏa khí tức quỷ dị và hóa thành vòng tròn nhân quả khiến đại kiếm tan rã. Hắn tuyên bố viễn cổ kiếm ý của Hứa Lập Quốc có nhân là do mình, nên quả phải thuộc về mình, khiến Hứa Lập Quốc hoảng sợ cầu xin và cố dùng chính lý nhân quả để phản biện nhưng không lay chuyển được Vương Lâm."},{"chuong":689,"tieuDe":"Đại Viên Mãn Và Ác Thú Hứa Lập Quốc","tomTat":"Côn Cực Tiên dung nhập vào hư vô của ý cảnh, khiến Hứa Lập Quốc hoảng sợ khuất phục và vội nịnh nọt Vương Lâm. Vương Lâm cho hắn tạm hoạt động trong phạm vi quanh Hoành Vân Phong để lĩnh ngộ viễn cổ kiếm ý, đồng thời thả Văn Thú, Lôi Oa và Xạ Thần Xa, khiến Xạ Thần Xa hóa thành Lôi Thú rồi đối địch với Lôi Oa. Sau đó, Vương Lâm chuyển trọng tâm từ tế luyện pháp bảo sang rà soát thần thông, nhận ra Trảm La Quyết, Định Thân Thuật, ba chỉ pháp Tịch Diệt, Hóa Ma, Hoàng Tuyền và tam thức đạo niệm Hoàng Tuyền cần được điều chỉnh theo cảm nhận về bước thứ ba. Trong hai năm hắn suy luận không ngừng, Hứa Lập Quốc lén dùng ảo thuật lừa tu sĩ quanh vùng, rồi khi Trương Tân Hải dẫn con tới giao oán khí, hắn còn định tạm dung nhập thân thể người con nên bị Vương Lâm cấm túc. Vương Lâm chấp nhận con trai Trương Tân Hải làm sứ giả kế nhiệm, ban đan dược, giao nhiệm vụ thu oán khí định kỳ và đưa hạt giống Thăng Tiên Quả cho Trương gia gieo trồng trong mười năm. Oán khí phàm nhân được hấp thu vào Hoàng Tuyền, khiến thần thông này có bóng dáng Tuyền Hồn, còn sinh tử luân hồi ý cảnh của Vương Lâm đến năm thứ mười tám ở Thanh Linh Tinh thì hoàn toàn viên mãn. Cuối cùng, Vương Lâm bày trận tiên ngọc ở hoang mạc tây bắc Thanh Linh Tinh, dùng hết tiên ngọc rồi uống tiên dịch, đạt Vấn Đỉnh viên mãn sau mười chín năm tám tháng. Khi cảnh giới đã viên mãn, hắn lấy tiên bút kim quang vẽ liền tám nét ký hiệu, vượt cực hạn bảy nét trước kia và nhận ra uy lực tăng thêm một bậc."},{"chuong":690,"tieuDe":"Đoạt Lôi Đỉnh","tomTat":"Sau khi kết thúc việc ở Thanh Linh Tinh, Vương Lâm cưỡi Lôi Thú rời đi, mang theo Thăng Tiên Quả và ngọc giản chứa oán khí. Biết muốn vào Lôi Tiên Giới cần có Lôi Đỉnh, hắn không muốn dựa nhiều vào Thân Công Hổ nên quyết định tự đoạt một chiếc. Dựa vào ngọc giản của Thân Công Hổ, hắn chọn Thánh Đàn Tinh, nơi có hai gia tộc thường nhận nhiều Lôi Đỉnh, rồi ngồi chờ trong tinh không. Khi đội tu sĩ trở về, lão già Trương gia vừa đạt Âm Hư nghi hắn giả mạo sứ giả Lôi Tiên Điện và cự tuyệt yêu cầu giao đỉnh. Vương Lâm gọi khôi lỗi Tiên Vệ giao chiến, phá khiên lửa của đối phương, rồi lấy Tiên Sơn thi triển Trừu Linh Chi Lai khiến lão già kinh hãi. Chương kết khi Vương Lâm tiếp tục ngưng tụ lôi điện thực chất hóa trong tay phải, đẩy áp lực của trận đoạt đỉnh lên cao."},{"chuong":691,"tieuDe":"Có Lợi Hơn Rất Nhiều","tomTat":"Vương Lâm áp đảo lão già Âm Hư, đoạt lấy Lôi Đỉnh rồi không rời đi ngay mà muốn đổi lấy thần thông Đệ Tam Nhãn. Ban đầu lão già chê Tịch Diệt Chỉ và Hóa Ma Chỉ, nhưng khi Vương Lâm dùng khôi lỗi Tiên Vệ bắt mãnh thú và thi triển Sát Lục Tiên Quyết, lão nhận ra giá trị công thủ của thuật này. Sau khi Vương Lâm giả vờ bỏ đi, lão già đồng ý đổi Đệ Tam Nhãn lấy ba thuật, nhưng cố ý ghi sai vài chỗ trong ngọc giản. Vương Lâm nhìn ra mưu tính đó, cảnh báo giới hạn Sát Lục Chi Khí rồi rời đi, trong lòng cho rằng mình lời lớn vì Đệ Tam Nhãn ẩn chứa phương hướng bước thứ ba. Trở lại Hoành Vân Phong, hắn tu chỉnh Đệ Tam Nhãn hơn nửa tháng. Khi Lôi Đỉnh dẫn Tiên Lôi chuẩn bị đưa hắn vào Lôi Tiên Giới, Vương Lâm cố ý thu đỉnh và nuốt hai đạo Tiên Lôi để hấp thụ nguyên lực."},{"chuong":692,"tieuDe":"Chưa Ai Từng Làm","tomTat":"Trên Thanh Linh Tinh, mây sấm không tan sau hai đạo Tiên Lôi mà tiếp tục ngưng tụ thành đạo thứ ba mạnh hơn rất nhiều. Vương Lâm để nguyên thần mang Lôi Đỉnh bay lên, hóa hình có vài phần giống Thái Cổ Lôi Long và nuốt một nửa đạo lôi. Phần lôi đình còn lại bị Lôi Đỉnh tiếp nhận, khiến chiếc đỉnh hút trọn cơn lốc sấm sét rồi nứt vỡ hoàn toàn. Sự kiện này tạo tiền lệ chưa từng có, làm Lôi Tiên Giới mất vĩnh viễn một Lôi Đỉnh và một chỉ tiêu tiến vào. Cuồng lôi từ Lôi Đỉnh vỡ cuốn lấy Vương Lâm, phá nát hư không và kéo hắn tới cửa Lôi Tiên Giới với tốc độ dữ dội. Trên đường, nhiều tu sĩ La Thiên Tinh Vực đang được lôi quang dẫn dắt kinh hãi khi thấy luồng sao băng lôi đình lao vụt qua."},{"chuong":693,"tieuDe":"Lôi Tiên Giới","tomTat":"Trước cửa Lôi Tiên Giới, các tu sĩ nhìn thấy lối vào không phải cánh cửa bình thường mà là đạo sấm sét đỏ sậm khổng lồ, theo truyền thuyết do tiên hồn sau khi tiên giới sụp đổ hóa thành. Nhiều sứ giả Lôi Tiên Điện và độc tu La Thiên Tinh Vực khoanh chân chờ cửa mở, trong đó có Thân Công Hổ. Đường Ngôn Phong mỉa mai Thân Công Hổ vì phụ thuộc Tôn Chủ và đạo hồn không đầy đủ, nhưng Thân Công Hổ không hối hận dù từng chịu áp lực từ gia tộc và Lôi Tiên Điện. Đúng lúc đó, sao băng lôi đình của Vương Lâm lao tới với tốc độ khiến thần thức mọi người không kịp bắt, va thẳng vào sấm sét đỏ sậm và biến mất vào trong trước khi cửa mở. Một tu sĩ Âm Hư dùng phân thân thử cửa liền bị tia chớp truy diệt cả thân thể, nguyên thần và túi trữ vật. Thân Công Hổ nhờ đạo hồn cảm nhận khí tức Tôn Chủ trong sao băng, còn bên trong Lôi Tiên Giới, một lão già tóc bạc trên lôi sơn đen cảm ứng dị biến rồi hóa thành tinh điểm biến mất."},{"chuong":694,"tieuDe":"Người Có Duyên","tomTat":"Lưu tinh lôi đình kéo Vương Lâm xuyên vào tia chớp đỏ sậm của Lôi Tiên Giới, lôi lực tăng mạnh khóa chặt thân thể và nguyên thần rồi nện hắn xuống một vùng đại lục. Vương Lâm trọng thương dưới đáy hố, trong khi lão giả tóc bạc xuất hiện bên miệng hố, nhận ra nguyên thần và thân thể hắn đều liên quan lôi điện, còn cảnh báo con đường này có thể khiến hắn thành lôi linh. Thấy vị trí Vương Lâm rơi xuống có chút thú vị, lão xem là có duyên và dùng thần thông tác động vào mặt đất trước khi biến mất. Vương Lâm tỉnh lại trong thạch thất sụp đổ dưới lòng đất, phát hiện một tia lôi lực không hòa hợp trong nguyên thần nên thổ nạp bảy ngày để khu trừ, có khôi lỗi Tiên Vệ hộ pháp. Khi thử thoát ra, hắn bị bùn đất chứa thiên địa nguyên lực bắn ngược, nhận ra có người cố ý giam cầm các hướng. Không còn lựa chọn, hắn lấy tiên bút, dùng tiên lực mở đường vào thông đạo phía trước, nhưng các cửa ra liên tục lóe sáng rồi biến mất trước khi hắn tiếp cận."},{"chuong":695,"tieuDe":"Muốn Giết Người !","tomTat":"Vương Lâm nhiều lần vồ hụt cửa ra trong thông đạo dưới lòng đất, từ đó nhận ra cánh cửa có người điều khiển và mình đang bị một loại thần thông trêu chọc, giam khốn. Ở một nơi trong Lôi Tiên Giới, một lão giả tóc bạc quan sát hắn, gọi hắn là tiểu bối có duyên và đặt hạn bảy ngày để xem hắn có thể thoát ra hay không. Vương Lâm không tiếp tục đuổi theo từng cửa ra mà dùng ba ngày đi hết hệ thống thông đạo, ghi nhớ địa hình thành bản đồ trong đầu rồi chọn điểm trung tâm để phá cục. Hắn gọi Xạ Thần Xa hóa thành Lôi Thú, để con rối Tiên Vệ và tiên kiếm có Hứa Lập Quốc cùng công kích tầng bùn đất, sau đó tự vận tiên lực và lôi uy trong nguyên thần đánh tiếp, khiến các thông đạo sụp đổ dây chuyền. Tuy vậy, mạng thiên địa nguyên lực tạo cửa ra vẫn không tan, chứng tỏ thần thông của đối phương vượt ngoài cấu trúc đất đá. Nhờ bùn đất không còn ngăn trở, khi cửa tiếp theo hiện ra, Vương Lâm lập tức lao qua cùng Tiên Vệ và Lôi Thú, thoát ra hư không. Sau khi rời khỏi khu vực bị nhốt, hắn suy đoán nơi này là Lôi Tiên Giới và hệ thống hóa các cơ duyên khiến tu sĩ khao khát tiến vào, gồm tiên đan, tiên bảo, tiên thuật hoàn chỉnh, thi thể tiên nhân, vũng nguyên lực và nguyên khí."},{"chuong":696,"tieuDe":"Đông Lâm Hứa Gia","tomTat":"Sau khi thoát khỏi nơi bị nhốt và suy ngẫm về bí mật của Lôi tiên giới, Vương Lâm phát hiện dưới lớp bùn đất một mảnh vỡ màu xám trắng to bằng nắm tay, phát ra dao động tiên lực như một phần của cái bình. Ở một mảnh đại lục nhỏ khác, lão giả tóc trắng nhận ra Vương Lâm đã dùng mánh khóe thoát sớm nhưng tạm bỏ qua, tiếp tục kế hoạch thu hồn tiên sơn và bố trí La Thiên đại trận. Ông bộc lộ dã tâm sau khi kế hoạch hoàn thành sẽ trở thành đệ nhất La Thiên tinh vực, quét ngang Liên Minh Tinh Vực và giết Trọng Huyền Tử. Khi Vương Lâm thu mảnh vỡ vào túi trữ vật, một thanh niên áo tím đứng trên ma ảnh đầu một sừng xuất hiện, dùng ma khí uy hiếp hắn giao vật. Hai bên giao chiến; đối phương dùng mưa tên, ma ảnh thôn lôi cầu và trường thương nước ma khí, còn Vương Lâm mượn lôi lực Lôi tiên giới để phản kích. Trước màn nước ma khí, Vương Lâm lấy đá núi tiên giới, rút hồn phách tiên thạch thành sương mù tiên khí, xuyên thủng phòng tuyến và lao tới tiếp tục tấn công."},{"chuong":697,"tieuDe":"Tuyệt Luân, Đạo Niệm Chi Chiến","tomTat":"Đám sương do hồn phách tiên thạch biến thành bao vây trường thương, trong khi Vương Lâm kích nổ lôi cầu từng bị ma ảnh nuốt để phá tan ma ảnh từ bên trong. Hắn lập tức điều Tiên Vệ lao ra tung một quyền đỉnh phong, ép Hứa Phong Hàn phải phun nguyên thần tinh huyết và thi triển Đông Lâm chi mạc để giữ mạng. Va chạm làm đại lục chấn động, Tiên Vệ bị suy yếu rõ rệt, còn Hứa Phong Hàn lộ tên trong trạng thái chật vật và nổi sát ý. Vương Lâm nhận ra tu sĩ Âm Hư khó giết, tranh thủ thu các mảnh vỡ pháp bảo lộ ra dưới bùn đất vào túi trữ vật. Hứa Phong Hàn chuyển sang đạo niệm hóa ma, thi triển Đạo hóa Ma Liên, đệ nhất chuyển, khiến ma diễm phủ trời và áp lực như thiên địa cùng vận động. Vương Lâm dùng Hoàng Tuyền hiện giữa không trung để vây Ma Liên, hóa giải cảm giác thiên địa xoay chuyển. Hứa Phong Hàn vì thấy Vương Lâm có đạo niệm ngưng thật, nhiều pháp bảo và thủ đoạn rút hồn phách đá núi nên suy đoán hắn là tu sĩ bước thứ hai bị tụt tu vi. Trận chiến tiếp tục khi Hứa Phong Hàn thúc ma diễm lao tới, còn Vương Lâm đáp bằng Thức thứ hai, ngưng tụ tuyền hồn."},{"chuong":698,"tieuDe":"Cưu Chiếm Thước Sào","tomTat":"Oán niệm phàm nhân trên Thanh Linh tinh do Vương Lâm ngưng tụ tràn ra từ Hoàng Tuyền, hóa thành vô số hư ảnh rồi hợp nhất thành một oan hồn đối kháng ma diễm của Hứa Phong Hàn. Va chạm làm Hoàng Tuyền tan nát, đạo niệm Vương Lâm bị tổn thương và khiến hắn phun máu, nhưng hắn dùng ý chí bất khuất tái ngưng tụ Hoàng Tuyền. Hứa Phong Hàn cũng bị oán niệm ăn mòn tâm trí, phải áp chế các ý niệm hỗn tạp và bắt đầu xem Vương Lâm là đối thủ ngang hàng. Khi Ma Liên bách chuyển ép Vương Lâm lùi lại, Hoàng Tuyền lực tạo lực hút làm chậm liên hoa, rồi Roi nhân quả đánh trúng sơ hở tâm thần Hứa Phong Hàn. Vương Lâm không đánh thẳng đối phương mà đạp lên, rồi khoanh chân ngồi trên Ma Liên, khiến Hứa Phong Hàn thừa nhận đã bại trong chiến đạo niệm. Không chịu dừng lại, Hứa Phong Hàn thi triển Nguyên Hóa Ma Thần bằng thiên địa nguyên lực; Vương Lâm mở con mắt thứ ba chuẩn bị ứng đối, nhưng ma vật một sừng vừa hiện ra đã quay lại cắn và nuốt chính Hứa Phong Hàn."},{"chuong":699,"tieuDe":"Ma Liên","tomTat":"Vương Lâm đối mặt ma vật đang bao lấy Hứa Phong Hàn, mở con mắt thứ ba để soi rõ bên trong rồi dùng Định thân thuật phối hợp Trảm La Quyết chém đứt thần thông, khiến ma vật tan rã và Hứa Phong Hàn tuyệt khí. Hắn thu mảnh vỡ pháp bảo, rời xa chiến trường tới Lôi Sơn mở động phủ, luyện hóa hai đạo tiên lôi để bù nguyên lực hao tổn. Trong lúc nghiên cứu Ma Liên, Vương Lâm phát hiện nó là không gian trữ vật do đạo niệm tạo thành, nuốt ma hồn bên trong để hồi phục và tinh tiến nguyên lực. Hắn lấy được dược bình khắc chữ Hứa chứa đan dược tiên khí nồng đậm cùng một lá bùa có ký hiệu mực đỏ, sau đó Ma Liên héo rũ tiêu tan. Ở La Thiên Tinh Vực, Diêu Không trở về Diêu gia xin nhận tổ quy tông để cầu cứu cho Diêu Tích Huyết; tổ phụ Diêu gia tính ra nàng ở Lôi Tiên Giới và giao lệnh bài để hắn tới Lôi Tiên Điện. Vương Lâm rời động phủ tiếp tục thăm dò Lôi Tiên Giới, nhận ra nơi này không thể dựa vào truyền tống trận, rồi gặp hai tu sĩ Vấn Đỉnh đại viên mãn nhưng đôi bên tránh xung đột."},{"chuong":700,"tieuDe":"Lý Nguyên!","tomTat":"Sau một tháng tìm kiếm trên đại lục vỡ trong Lôi Tiên Giới mà không có manh mối, Vương Lâm quay về đường cũ và phát hiện một trận pháp cấm chế mới xuất hiện. Hắn nhìn ra tiên lực trong cấm chế có sơ hở nhưng lập tức nghi đây là bố cục cố ý, nên giả vờ rời đi để quan sát. Khi hắn biến mất, Lý Nguyên và nữ tu Vấn Đỉnh đại viên mãn lộ diện; qua đối thoại, Lý Nguyên cho biết mệnh hồn của mình nằm trong tay gia tộc nữ tu và từng được tổ phụ nàng ban đan dược cứu mạng. Một tu sĩ trung niên sau đó dùng hình nhân mộc linh phá cấm chế, làm lộ cửa động, nhưng vừa xông vào đã bị tồn tại bên trong nuốt cả thân thể lẫn nguyên thần. Nữ tu tỏ ra hưng phấn với thú cưng trong hang và muốn tiếp tục cho nó ăn no tại Lôi Tiên Giới. Vương Lâm lúc này hiện thân, chứng tỏ hắn chưa hề mắc bẫy; nữ tu dùng quạt lông công kích còn Lý Nguyên thi triển mười tám cấm chế liên hoàn. Vương Lâm phóng lôi đình từ ngón trỏ phá tan lông chim khiến nữ tu thổ huyết, rồi ngưng lôi quang thành chưởng ấn hư ảo để đối diện hệ cấm chế quỷ dị của Lý Nguyên."},{"chuong":701,"tieuDe":"Mũi Kiếm","tomTat":"Vương Lâm phá tan mười tám cấm chế trong hang, đánh Lý Nguyên thổ huyết rồi dùng Nhân Quả Chi Tiên bắt Thiên Quỷ đang hóa đầu lâu xanh lục, ném nó vào Tôn Hồn Phiên để phục vụ luyện chế Tiên Vệ thứ hai. Trước uy thế ấy, Lý Nguyên nhận sai và dùng tin tức về một bí địa có cấm chế trong Lôi Tiên Giới để cầu hòa, đồng thời giao ngọc giản chứa phương pháp cấm chế ẩn giấu thân hình. Vương Lâm không lấy hồn Lý Nguyên mà rút một phần hồn nữ tử họ Cát làm tín vật, khiến hai người bị ràng buộc phải dẫn đường. Trên đường, Lý Nguyên dùng cấm chế bao bọc thần thức để trấn an nữ tử họ Cát, còn Vương Lâm vẫn nghi lời hắn nửa thật nửa giả và chuẩn bị sát ý nếu phát hiện bất lợi. Ba người tới rìa đại lục Lôi Tiên Giới, nơi các mảnh đại lục vỡ được vô số xích lôi nối trong hư vô, khiến Vương Lâm liên tưởng tới sự sụp đổ của tiên giới. Nữ tử họ Cát lấy thiết kiếm đen gia truyền, dùng máu kích hoạt quầng sáng để chở Lý Nguyên vượt xích lôi; phản ứng của Lý Nguyên với thanh kiếm khiến Vương Lâm nhận ra quan hệ giữa hắn và kiếm không bình thường. Vương Lâm tự bước trên sợi xích lôi quang như đi trên đất bằng, hấp thu lôi đình rồi dần khống chế hiện tượng lôi quang bùng sáng, đồng thời suy đoán việc Lý Nguyên phục vụ Cát gia có thể là một kế hoạch liên quan tới thanh thiết kiếm."},{"chuong":702,"tieuDe":"Rất Tốt, Rất Tốt","tomTat":"Vương Lâm cùng Lý Nguyên và Cát Hồng tiếp tục đi sâu trong hư vô Lôi Tiên Giới bằng thanh thiết kiếm, nhận ra vật này chống chịu lôi quang rất mạnh. Hành trình kéo dài gần hai tháng không gặp tu sĩ nào, trong lúc đó Cát Hồng vừa sợ Vương Lâm vì hồn mình bị hắn nắm giữ, vừa nhiều lần cảm thấy bóng dáng Lý Nguyên quen thuộc khó hiểu. Khi lôi quang càng nồng đậm, sợi xích lôi đình bắt đầu chấn động dữ dội, khiến Vương Lâm cảm thấy phía trước có tồn tại đáng sợ. Lý Nguyên cảnh báo hiện tượng sợi xích lay động có thể làm các mảnh vỡ đại lục sụp đổ, nhưng Vương Lâm vẫn quyết định tiến tới để tìm câu trả lời. Phía trước, họ gặp đám sương mù tiên khí vô biên chắn đường; Lý Nguyên dùng la bàn tính toán cấm chế nhưng la bàn nổ tung. Hắn xác định đó là cấm chế thiên cấp trung phẩm, lấy Lôi Tiên Giới làm nền và hình thành đại trận có thể luyện hóa vạn vật. Cuối chương, một lão già bí ẩn cầm sợi xích lôi quang bước ra từ trong sương mù, nói rằng có duyên và đang muốn tìm đối phương."},{"chuong":703,"tieuDe":"Bao Nhiêu Thành","tomTat":"Vương Lâm cùng Lý Nguyên, Cát Hồng gặp một lão già thần bí cầm Lôi quang thiết liên trong Lôi tiên giới. Lão chỉ thẳng Vương Lâm là người hữu duyên vì đã thoát khỏi thông đạo trong bảy ngày, đồng thời để lộ chính mình là người bố trí thông đạo ấy. Khi lão chộp tay định bắt, Vương Lâm dùng thần thông máu huyết học ở mảnh đất Yêu Linh để thuấn di thoát thân, nhưng lão lập tức thi triển Đảo ngược khiến phương hướng đảo lộn và kéo hắn trở lại trước mặt. Lão phát hiện Lôi thú sừng bạc trong túi trữ vật của Vương Lâm, cưỡng ép mượn đi và tuyên bố lôi thú của người tiến vào Lôi tiên giới đều tạm thuộc về mình. Sau đó lão ngưng tụ vô số hạt bụi thành quả cầu sáng, bắn vào ngực Vương Lâm để giúp hắn tu luyện lôi nguyên thần và lôi thể. Cuối cùng lão phất tay dùng nguồn lực cực mạnh cuốn Vương Lâm, Lý Nguyên và Cát Hồng xuyên qua sương mù, rồi tự lẩm bẩm không biết mình vừa dùng bao nhiêu thành lực."},{"chuong":704,"tieuDe":"Thiêu Đốt","tomTat":"Vương Lâm, Lý Nguyên và Cát Hồng đáp xuống một đại lục trong Lôi tiên giới sau lần di chuyển cực nhanh; Lý Nguyên tái nhợt, Cát Hồng nôn mửa, còn Vương Lâm lập tức bị cơn đau dữ dội từ quả cầu ánh sáng trong lồng ngực lan khắp thân thể. Thấy hắn bất ổn, Cát Hồng lấy chủy thủ màu đen truyền thừa gia tộc định ám toán, nhưng bị ánh mắt và lời uy hiếp của hắn làm hoảng sợ, ném chủy thủ xuống đất để hắn thu lấy. Quả cầu ánh sáng do lão già ngưng tụ vừa thiêu đốt đau đớn vừa không làm hại tu vi, ngược lại còn thúc đẩy tu vi Vương Lâm tiến gần Vấn Đỉnh đại viên mãn. Vương Lâm nhận ra thân thể mình đang nghịch chuyển từ trạng thái lôi điện về máu thịt, hiểu rằng khi quá trình hoàn tất thì cơn đau sẽ biến mất và tu vi sẽ vượt qua cánh cửa tu đạo đầu tiên, nên chủ động hít sâu để tăng đau nhằm tăng tốc tiến cảnh. Hắn không giết Cát Hồng vì suy đoán việc nàng vào được Lôi tiên giới và việc Lý Nguyên chưa đoạt thanh thiết kiếm đều ẩn chứa nguyên nhân. Lý Nguyên âm thầm dùng cấm chế trên mi tâm quan sát Vương Lâm, cho rằng tu vi hắn càng cao càng có lợi nhưng không thể để đạt Âm Dương hư thực trước khi tới nơi cần tìm. Sau một tháng tới trung tâm đại lục, Lý Nguyên xác định cấm chế nằm về phía đông; ba người tiếp tục xuyên qua Lôi quang Thiên liên trong hư vô, ba tháng sau tới trước một ngọn núi cao vút trong mây mà Lý Nguyên kích động xác nhận chính là địa điểm cần tìm."},{"chuong":705,"tieuDe":"Gây Khó Dễ","tomTat":"Vương Lâm, Lý Nguyên và Cát Hồng tới một ngọn núi cực cao trong Lôi tiên giới, nơi sấm sét dày đặc và cấm chế bao phủ. Khi nhìn bóng lưng Lý Nguyên và ngọn núi, Cát Hồng nhận ra bí mật của Cát gia: từng có tộc nhân vào Lôi tiên giới mấy vạn năm trước không trở về, còn việc nàng được truyền pháp bảo và đưa vào đây có liên quan tới chuộc tội cùng hiến tế hồn phách. Vương Lâm quan sát phản ứng của nàng và suy ra Lý Nguyên đã sớm chú ý tới mình, dùng cấm chế dẫn hắn xuất hiện và đưa mọi việc vào kế hoạch. Lý Nguyên thừa nhận việc gặp Vương Lâm nằm trong bố cục, tiết lộ sâu trong núi có chủ nhân của mình và cảnh báo Vương Lâm không thể rời đi nếu không được cho phép. Vương Lâm lập tức gọi Tiên Vệ khôi lỗi đánh mở dòng chảy thông ra ngoài, rồi phóng kiếm khí của Lăng Thiên Hậu dừng trước mi tâm Lý Nguyên để phá thế uy hiếp. Sau đó hắn nói rõ mục tiêu thật sự không phải Nguyên khí mơ hồ mà là Mai hoa thuật, cấm chế cổ đã thất truyền mà hắn nghi Lý Nguyên đang nắm giữ."},{"chuong":706,"tieuDe":"Chuôi Kiếm Và Mũi Kiếm","tomTat":"Khi đã tới ngọn núi mục tiêu, Vương Lâm ép Lý Nguyên giao trước phần đầu Mai Hoa thuật, khiến Lý Nguyên phải đưa ngọc giản chứa Mai hoa thập tam cấm và hẹn giao thêm năm loại sau khi vào núi. Trên đường lên núi, Lý Nguyên giải thích nguồn gốc cấm chế, bốn cấp Thiên, Địa, Huyền, Hoàng và cấp Hư gồm tứ đại cấm thuật, đồng thời nói ngọn núi này do tứ đại cấm thuật tan vỡ tạo nên nên không có điểm cuối nếu không biết hóa giải. Hắn nhiều lần thi triển cấm chế làm ngọn núi chấn động và thu nhỏ, trong lúc Cát Hồng hoảng sợ cầu cứu Vương Lâm rồi tố Lý Nguyên tới Cát gia có mục đích. Để cầu sống, Cát Hồng giao họa trục, thiết kiếm và la bàn; Lý Nguyên nhận ba vật, đặc biệt trân trọng họa trục vẽ ngọn núi, phi kiếm, người trên chuôi kiếm và bóng người trên mũi kiếm giống hắn, rồi để nàng bỏ chạy. Sau nhiều lần phá cấm, Lý Nguyên đưa Vương Lâm tới đỉnh núi, nơi có tượng đá trung niên nam tử, thanh phi kiếm và người đứng trên mũi kiếm. Khi Vương Lâm nhìn ấn quyết trên cánh tay tượng đá, tâm thần hắn bị hút vào huyễn cảnh Tiên giới, thấy các tiên nhân lôi điện giao chiến và một thanh bảo kiếm tím xuất hiện. Trong huyễn cảnh, nam tử đứng trên chuôi kiếm tuyên bố linh hồn bất diệt rồi tan rã, còn người hầu trên mũi kiếm đau thương lao theo lên trời, khép lại bằng ý niệm chủ chết thì đầy tớ đi theo."}];
